import java.util.*;
import java.io.*;
import com.google.gson.*;
import com.google.gson.reflect.TypeToken;

class Calculator {
    private double result;

    public Calculator(double initial) {
        this.result = initial;
    }

    public Calculator add(double value) {
        this.result += value;
        return this;
    }

    public Calculator subtract(double value) {
        this.result -= value;
        return this;
    }

    public Calculator multiply(double value) {
        this.result *= value;
        return this;
    }

    public Calculator divide(double value) {
        if (value == 0) {
            throw new RuntimeException("Division by zero is not allowed");
        }
        this.result /= value;
        return this;
    }

    public Calculator power(double value) {
        this.result = Math.pow(this.result, value);
        return this;
    }

    public double getResult() {
        return this.result;
    }
}

class Main {
    public static double solution(double initial, String[][] operations) {
        Calculator calc = new Calculator(initial);
        for (String[] op : operations) {
            String method = op[0];
            double value = Double.parseDouble(op[1]);
            if (method.equals("add")) {
                calc.add(value);
            } else if (method.equals("subtract")) {
                calc.subtract(value);
            } else if (method.equals("multiply")) {
                calc.multiply(value);
            } else if (method.equals("divide")) {
                calc.divide(value);
            } else if (method.equals("power")) {
                calc.power(value);
            }
        }
        return calc.getResult();
    }

    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        double initial = Double.parseDouble(sc.nextLine().trim());
        String opsLine = sc.nextLine().trim();

        Gson gson = new Gson();
        Type type = new TypeToken<String[][]>(){}.getType();
        String[][] operations = gson.fromJson(opsLine, type);

        double result = solution(initial, operations);
        System.out.println(result);
    }
}

