#include <iostream>
#include <vector>
#include <string>
#include <cmath>
#include <sstream>
#include <regex>
using namespace std;

class Calculator {
private:
    double result;

public:
    Calculator(double initial) : result(initial) {}

    Calculator& add(double value) {
        result += value;
        return *this;
    }

    Calculator& subtract(double value) {
        result -= value;
        return *this;
    }

    Calculator& multiply(double value) {
        result *= value;
        return *this;
    }

    Calculator& divide(double value) {
        if (value == 0) {
            throw runtime_error("Division by zero is not allowed");
        }
        result /= value;
        return *this;
    }

    Calculator& power(double value) {
        result = pow(result, value);
        return *this;
    }

    double getResult() {
        return result;
    }
};

vector<pair<string, double>> parseOperations(string line) {
    vector<pair<string, double>> operations;
    regex pattern(R"(\["(\w+)",([^\]]+)\])");
    sregex_iterator iter(line.begin(), line.end(), pattern);
    sregex_iterator end;

    for (; iter != end; ++iter) {
        smatch match = *iter;
        string method = match[1];
        double value = stod(match[2]);
        operations.push_back({method, value});
    }
    return operations;
}

double solution(double initial, vector<pair<string, double>> operations) {
    Calculator calc(initial);
    for (auto& op : operations) {
        string method = op.first;
        double value = op.second;
        if (method == "add") {
            calc.add(value);
        } else if (method == "subtract") {
            calc.subtract(value);
        } else if (method == "multiply") {
            calc.multiply(value);
        } else if (method == "divide") {
            calc.divide(value);
        } else if (method == "power") {
            calc.power(value);
        }
    }
    return calc.getResult();
}

int main() {
    double initial;
    cin >> initial;
    cin.ignore();

    string line;
    getline(cin, line);

    vector<pair<string, double>> operations = parseOperations(line);

    double result = solution(initial, operations);
    cout << result << endl;
    return 0;
}

