package main

import (
    "bufio"
    "encoding/json"
    "fmt"
    "math"
    "os"
    "strconv"
    "strings"
)

type Calculator struct {
    result float64
}

func NewCalculator(initial float64) *Calculator {
    return &Calculator{result: initial}
}

func (c *Calculator) Add(value float64) *Calculator {
    c.result += value
    return c
}

func (c *Calculator) Subtract(value float64) *Calculator {
    c.result -= value
    return c
}

func (c *Calculator) Multiply(value float64) *Calculator {
    c.result *= value
    return c
}

func (c *Calculator) Divide(value float64) *Calculator {
    if value == 0 {
        panic("Division by zero is not allowed")
    }
    c.result /= value
    return c
}

func (c *Calculator) Power(value float64) *Calculator {
    c.result = math.Pow(c.result, value)
    return c
}

func (c *Calculator) GetResult() float64 {
    return c.result
}

func solution(initial float64, operations [][]interface{}) float64 {
    calc := NewCalculator(initial)
    for _, op := range operations {
        method := op[0].(string)
        value := op[1].(float64)
        switch method {
        case "add":
            calc.Add(value)
        case "subtract":
            calc.Subtract(value)
        case "multiply":
            calc.Multiply(value)
        case "divide":
            calc.Divide(value)
        case "power":
            calc.Power(value)
        }
    }
    return calc.GetResult()
}

func main() {
    reader := bufio.NewReader(os.Stdin)

    initialStr, _ := reader.ReadString('\n')
    initial, _ := strconv.ParseFloat(strings.TrimSpace(initialStr), 64)

    opsStr, _ := reader.ReadString('\n')
    var operations [][]interface{}
    json.Unmarshal([]byte(strings.TrimSpace(opsStr)), &operations)

    result := solution(initial, operations)
    fmt.Println(result)
}

