#include <math.h>
#include <string.h>

typedef struct {
    double result;
} Calculator;

Calculator* createCalculator(double initial) {
    Calculator* calc = (Calculator*)malloc(sizeof(Calculator));
    calc->result = initial;
    return calc;
}

Calculator* add(Calculator* calc, double value) {
    calc->result += value;
    return calc;
}

Calculator* subtract(Calculator* calc, double value) {
    calc->result -= value;
    return calc;
}

Calculator* multiply(Calculator* calc, double value) {
    calc->result *= value;
    return calc;
}

Calculator* divide(Calculator* calc, double value) {
    if (value == 0) {
        printf("Division by zero is not allowed\n");
        exit(1);
    }
    calc->result /= value;
    return calc;
}

Calculator* power(Calculator* calc, double value) {
    calc->result = pow(calc->result, value);
    return calc;
}

double getResult(Calculator* calc) {
    return calc->result;
}

typedef struct {
    char method[20];
    double value;
} Operation;

int parseOperations(char* line, Operation* operations) {
    int count = 0;
    char* ptr = line;

    while (*ptr && count < 100) {
        if (*ptr == '[' && *(ptr+1) == '"') {
            ptr += 2;
            int i = 0;
            while (*ptr != '"' && i < 19) {
                operations[count].method[i++] = *ptr++;
            }
            operations[count].method[i] = '\0';

            while (*ptr != ',' && *ptr) ptr++;
            if (*ptr == ',') ptr++;

            operations[count].value = strtod(ptr, &ptr);
            count++;

            while (*ptr && *ptr != '[') ptr++;
        } else {
            ptr++;
        }
    }
    return count;
}

double solution(double initial, Operation* operations, int opCount) {
    Calculator* calc = createCalculator(initial);
    for (int i = 0; i < opCount; i++) {
        if (strcmp(operations[i].method, "add") == 0) {
            add(calc, operations[i].value);
        } else if (strcmp(operations[i].method, "subtract") == 0) {
            subtract(calc, operations[i].value);
        } else if (strcmp(operations[i].method, "multiply") == 0) {
            multiply(calc, operations[i].value);
        } else if (strcmp(operations[i].method, "divide") == 0) {
            divide(calc, operations[i].value);
        } else if (strcmp(operations[i].method, "power") == 0) {
            power(calc, operations[i].value);
        }
    }
    double result = getResult(calc);
    free(calc);
    return result;
}

int main() {
    double initial;
    scanf("%lf", &initial);
    getchar();

    char line[1000];
    fgets(line, sizeof(line), stdin);

    Operation operations[100];
    int opCount = parseOperations(line, operations);

    double result = solution(initial, operations, opCount);
    printf("%f\n", result);
    return 0;
}

