    "fmt"
    "math"
    "os"
    "strconv"
    "strings"
)

type Calculator struct {
    result float64
}

func NewCalculator(initial float64) (*Calculator, error) {
    if math.IsNaN(initial) || math.IsInf(initial, 0) {
        return nil, errors.New("initial value must be a valid number")
    }
    return &Calculator{result: initial}, nil
}

func (c *Calculator) validateNumber(value float64) error {
    if math.IsNaN(value) || math.IsInf(value, 0) {
        return errors.New("value must be a valid number")
    }
    return nil
}

func (c *Calculator) Add(value float64) (*Calculator, error) {
    if err := c.validateNumber(value); err != nil {
        return c, err
    }
    c.result += value
    return c, nil
}

func (c *Calculator) Subtract(value float64) (*Calculator, error) {
    if err := c.validateNumber(value); err != nil {
        return c, err
    }
    c.result -= value
    return c, nil
}

func (c *Calculator) Multiply(value float64) (*Calculator, error) {
    if err := c.validateNumber(value); err != nil {
        return c, err
    }
    c.result *= value
    return c, nil
}

func (c *Calculator) Divide(value float64) (*Calculator, error) {
    if err := c.validateNumber(value); err != nil {
        return c, err
    }
    if value == 0 {
        return c, errors.New("Division by zero is not allowed")
    }
    c.result /= value
    return c, nil
}

func (c *Calculator) Power(value float64) (*Calculator, error) {
    if err := c.validateNumber(value); err != nil {
        return c, err
    }
    c.result = math.Pow(c.result, value)
    return c, nil
}

func (c *Calculator) GetResult() float64 {
    return c.result
}

func solution(initial float64, operations [][]interface{}) float64 {
    calc, _ := NewCalculator(initial)
    for _, op := range operations {
        method := op[0].(string)
        value := op[1].(float64)
        switch method {
        case "add":
            calc.Add(value)
