    return calc;
}

Calculator* power(Calculator* calc, double value) {
    if (!validateNumber(value)) {
        printf("Value must be a valid number\n");
        exit(1);
    }
    calc->result = pow(calc->result, value);
    return calc;
}

double getResult(Calculator* calc) {
    return calc->result;
}

typedef struct {
    char method[20];
    double value;
} Operation;

int parseOperations(char* line, Operation* operations) {
    int count = 0;
    char* ptr = line;

    while (*ptr && count < 100) {
        if (*ptr == '[' && *(ptr+1) == '"') {
            ptr += 2;
            int i = 0;
            while (*ptr != '"' && i < 19) {
                operations[count].method[i++] = *ptr++;
            }
            operations[count].method[i] = '\0';

            while (*ptr != ',' && *ptr) ptr++;
            if (*ptr == ',') ptr++;

            operations[count].value = strtod(ptr, &ptr);
            count++;

            while (*ptr && *ptr != '[') ptr++;
        } else {
            ptr++;
        }
    }
    return count;
}

double solution(double initial, Operation* operations, int opCount) {
    Calculator* calc = createCalculator(initial);
    for (int i = 0; i < opCount; i++) {
        if (strcmp(operations[i].method, "add") == 0) {
            add(calc, operations[i].value);
        } else if (strcmp(operations[i].method, "subtract") == 0) {
            subtract(calc, operations[i].value);
        } else if (strcmp(operations[i].method, "multiply") == 0) {
            multiply(calc, operations[i].value);
        } else if (strcmp(operations[i].method, "divide") == 0) {
            divide(calc, operations[i].value);
        } else if (strcmp(operations[i].method, "power") == 0) {
            power(calc, operations[i].value);
        }
    }
    double result = getResult(calc);
    free(calc);
    return result;
}

