    double initial;
    scanf("%lf", &initial);
    getchar();

    char line[1000];
    fgets(line, sizeof(line), stdin);

    Operation operations[100];
    int opCount = parseOperations(line, operations);

    double result = solution(initial, operations, opCount);
    printf("%f\n", result);
    return 0;
}

