// Definition for a Node
struct Node {
    int val;
    Node* left;
    Node* right;
    Node* parent;

    Node(int x) : val(x), left(nullptr), right(nullptr), parent(nullptr) {}
};

class Solution {
public:
    Node* flipBinaryTree(Node* root, Node* leaf) {
        if (!root || !leaf || root == leaf) {
            return leaf;
        }

        vector<Node*> path;
        findPath(root, leaf, path);

        // Reconstruct tree along the path from leaf to root
        for (int i = path.size() - 1; i > 0; i--) {
            Node* current = path[i];
            Node* parent = path[i - 1];

            // Remove current from parent's children
            if (parent->left == current) {
                parent->left = nullptr;
            } else {
                parent->right = nullptr;
            }

            // If current had a left child, move it to right
            if (current->left) {
                current->right = current->left;
            }

            // Make parent the left child of current
            current->left = parent;
            parent->parent = current;
        }

        leaf->parent = nullptr;
        updateParents(leaf);
        return leaf;
    }

private:
    bool findPath(Node* node, Node* target, vector<Node*>& path) {
        if (!node) return false;

        path.push_back(node);
        if (node == target) return true;

        if (findPath(node->left, target, path) || findPath(node->right, target, path)) {
            return true;
        }

        path.pop_back();
        return false;
    }

    void updateParents(Node* node) {
        if (node->left) {
            node->left->parent = node;
            updateParents(node->left);
        }
        if (node->right) {
            node->right->parent = node;
            updateParents(node->right);
        }
    }
};

