func flipBinaryTree(root *Node, leaf *Node) *Node {
    if root == nil || leaf == nil || root == leaf {
        return leaf
    }

    var path []*Node
    findPath(root, leaf, &path)

    // Reconstruct tree along the path from leaf to root
    for i := len(path) - 1; i > 0; i-- {
        current := path[i]
        parent := path[i-1]

        // Remove current from parent's children
        if parent.Left == current {
            parent.Left = nil
        } else {
            parent.Right = nil
        }

        // If current had a left child, move it to right
        if current.Left != nil {
            current.Right = current.Left
        }

        // Make parent the left child of current
        current.Left = parent
        parent.Parent = current
    }

    leaf.Parent = nil
    updateParents(leaf)
    return leaf
}

func findPath(node *Node, target *Node, path *[]*Node) bool {
    if node == nil {
        return false
    }

    *path = append(*path, node)
    if node == target {
        return true
    }

    if findPath(node.Left, target, path) || findPath(node.Right, target, path) {
        return true
    }

    *path = (*path)[:len(*path)-1]
    return false
}

func updateParents(node *Node) {
    if node.Left != nil {
        node.Left.Parent = node
        updateParents(node.Left)
    }
    if node.Right != nil {
        node.Right.Parent = node
        updateParents(node.Right)
    }
