// Definition for a Node.
struct Node {
    int val;
    int numNeighbors;
    struct Node** neighbors;
};

struct Node* createNode(int val) {
    struct Node* node = malloc(sizeof(struct Node));
    node->val = val;
    node->numNeighbors = 0;
    node->neighbors = malloc(sizeof(struct Node*) * 100);
    return node;
}

// Hash table for mapping original nodes to cloned nodes
struct HashNode {
    struct Node* original;
    struct Node* clone;
    struct HashNode* next;
};

struct HashNode* hashTable[1000];

int hash(struct Node* node) {
    return ((long)node) % 1000;
}

struct Node* getClone(struct Node* original) {
    int index = hash(original);
    struct HashNode* curr = hashTable[index];
    while (curr) {
        if (curr->original == original) {
            return curr->clone;
        }
        curr = curr->next;
    }
    return NULL;
}

void putClone(struct Node* original, struct Node* clone) {
    int index = hash(original);
    struct HashNode* newNode = malloc(sizeof(struct HashNode));
    newNode->original = original;
    newNode->clone = clone;
    newNode->next = hashTable[index];
    hashTable[index] = newNode;
}

struct Node* dfs(struct Node* node) {
    if (!node) return NULL;

    // Check if already cloned
    struct Node* existing = getClone(node);
    if (existing) return existing;

    // Create clone of current node
    struct Node* clone = createNode(node->val);
    putClone(node, clone);

    // Clone all neighbors
    for (int i = 0; i < node->numNeighbors; i++) {
        clone->neighbors[clone->numNeighbors++] = dfs(node->neighbors[i]);
    }

    return clone;
}

struct Node* cloneGraph(struct Node* node) {
    if (!node) return NULL;

    // Initialize hash table
    for (int i = 0; i < 1000; i++) {
        hashTable[i] = NULL;
    }

    return dfs(node);
}

