    return ((long)node) % 1000;
}

struct Node* getClone(struct Node* original) {
    int index = hash(original);
    struct HashNode* curr = hashTable[index];
    while (curr) {
        if (curr->original == original) {
            return curr->clone;
        }
        curr = curr->next;
    }
    return NULL;
}

void putClone(struct Node* original, struct Node* clone) {
    int index = hash(original);
    struct HashNode* newNode = malloc(sizeof(struct HashNode));
    newNode->original = original;
    newNode->clone = clone;
    newNode->next = hashTable[index];
    hashTable[index] = newNode;
}

struct Node* cloneGraph(struct Node* node) {
    if (!node) return NULL;

    // Initialize hash table
    for (int i = 0; i < 1000; i++) {
        hashTable[i] = NULL;
    }

    // Create clone of starting node
    struct Node* startClone = createNode(node->val);
    putClone(node, startClone);

    // BFS queue
    struct Node* queue[1000];
    int front = 0, rear = 0;
    queue[rear++] = node;

    while (front < rear) {
        struct Node* current = queue[front++];
        struct Node* currentClone = getClone(current);

        // Process all neighbors
        for (int i = 0; i < current->numNeighbors; i++) {
            struct Node* neighbor = current->neighbors[i];
            struct Node* neighborClone = getClone(neighbor);

            if (!neighborClone) {
                // Create clone for unvisited neighbor
                neighborClone = createNode(neighbor->val);
                putClone(neighbor, neighborClone);
                queue[rear++] = neighbor;
            }

            // Connect current clone to neighbor clone
            currentClone->neighbors[currentClone->numNeighbors++] = neighborClone;
        }
    }

    return startClone;
}

