vector<vector<int>> solution(vector<int>& nums) {
    vector<vector<int>> result;

    for (int num : nums) {
        bool placed = false;
        // Try to place num in existing rows
        for (auto& row : result) {
            if (find(row.begin(), row.end(), num) == row.end()) {
                row.push_back(num);
                placed = true;
                break;
            }
        }

        // If can't place in any existing row, create new row
        if (!placed) {
            result.push_back({num});
        }
    }

    return result;
}

