    for (int i = 0; i < numsSize; i++) {
        int placed = 0;
        // Try to place nums[i] in existing rows
        for (int j = 0; j < *returnSize; j++) {
            int found = 0;
            for (int k = 0; k < (*returnColumnSizes)[j]; k++) {
                if (result[j][k] == nums[i]) {
                    found = 1;
                    break;
                }
            }
            if (!found) {
                result[j] = (int*)realloc(result[j], ((*returnColumnSizes)[j] + 1) * sizeof(int));
                result[j][(*returnColumnSizes)[j]] = nums[i];
                (*returnColumnSizes)[j]++;
                placed = 1;
                break;
            }
        }

        // If can't place in any existing row, create new row
        if (!placed) {
            result[*returnSize] = (int*)malloc(sizeof(int));
            result[*returnSize][0] = nums[i];
            (*returnColumnSizes)[*returnSize] = 1;
            (*returnSize)++;
        }
    }

    return result;
}

