import java.util.*;
import java.io.*;

class Main {
    private static List<List<int[]>> graph;
    private static int signalSpeed;

    public static int[] solution(int[][] edges, int signalSpeed) {
        if (edges.length == 0) return new int[0];

        int n = edges.length + 1;
        graph = new ArrayList<>();
        Main.signalSpeed = signalSpeed;

        for (int i = 0; i < n; i++) {
            graph.add(new ArrayList<>());
        }

        // Build adjacency list
        for (int[] edge : edges) {
            int a = edge[0], b = edge[1], weight = edge[2];
            graph.get(a).add(new int[]{b, weight});
            graph.get(b).add(new int[]{a, weight});
        }

        int[] result = new int[n];

        // For each server as center
        for (int center = 0; center < n; center++) {
            int totalPairs = 0;
            List<Integer> subtreeCounts = new ArrayList<>();

            // Count valid nodes in each subtree
            for (int[] neighbor : graph.get(center)) {
                int count = dfsCount(center, neighbor[0], center, neighbor[1]);
                subtreeCounts.add(count);
            }

            // Calculate pairs between different subtrees
            for (int i = 0; i < subtreeCounts.size(); i++) {
                for (int j = i + 1; j < subtreeCounts.size(); j++) {
                    totalPairs += subtreeCounts.get(i) * subtreeCounts.get(j);
                }
            }

            result[center] = totalPairs;
        }

        return result;
    }

    private static int dfsCount(int center, int node, int parent, int distance) {
        int count = 0;
        if (distance % signalSpeed == 0 && node != center) {
            count = 1;
        }

        for (int[] neighbor : graph.get(node)) {
            if (neighbor[0] != parent) {
                count += dfsCount(center, neighbor[0], node, distance + neighbor[1]);
            }
        }

        return count;
    }

