package main

import (
    "bufio"
    "encoding/json"
    "fmt"
    "os"
    "strconv"
    "strings"
)

type Pair struct {
    Node   int
    Weight int
}

var graph [][]Pair
var globalSignalSpeed int

func dfsCount(center, node, parent, distance int) int {
    count := 0
    if distance%globalSignalSpeed == 0 && node != center {
        count = 1
    }

    for _, neighbor := range graph[node] {
        if neighbor.Node != parent {
            count += dfsCount(center, neighbor.Node, node, distance+neighbor.Weight)
        }
    }

    return count
}

func solution(edges [][]int, signalSpeed int) []int {
    if len(edges) == 0 {
        return []int{}
    }

    n := len(edges) + 1
    graph = make([][]Pair, n)
    globalSignalSpeed = signalSpeed

    // Build adjacency list
    for _, edge := range edges {
        a, b, weight := edge[0], edge[1], edge[2]
        graph[a] = append(graph[a], Pair{b, weight})
        graph[b] = append(graph[b], Pair{a, weight})
    }

    result := make([]int, n)

    // For each server as center
    for center := 0; center < n; center++ {
        totalPairs := 0
        var subtreeCounts []int

        // Count valid nodes in each subtree
        for _, neighbor := range graph[center] {
            count := dfsCount(center, neighbor.Node, center, neighbor.Weight)
            subtreeCounts = append(subtreeCounts, count)
        }

        // Calculate pairs between different subtrees
        for i := 0; i < len(subtreeCounts); i++ {
            for j := i + 1; j < len(subtreeCounts); j++ {
                totalPairs += subtreeCounts[i] * subtreeCounts[j]
            }
        }

        result[center] = totalPairs
    }

    return result
}

func main() {
    reader := bufio.NewReader(os.Stdin)

    line, _ := reader.ReadString('\n')
    line = strings.TrimSpace(line)

    var edges [][]int
    json.Unmarshal([]byte(line), &edges)

    line, _ = reader.ReadString('\n')
    signalSpeed, _ := strconv.Atoi(strings.TrimSpace(line))

    result := solution(edges, signalSpeed)

    resultBytes, _ := json.Marshal(result)
    fmt.Println(string(resultBytes))
}

