class SummaryRanges {
    constructor() {
        this.intervals = [];
    }

    addNum(value) {
        // Check if value already exists
        for (const interval of this.intervals) {
            if (interval[0] <= value && value <= interval[1]) {
                return;
            }
        }

        // Find insertion position
        let pos = 0;
        while (pos < this.intervals.length && this.intervals[pos][1] < value) {
            pos++;
        }

        let newStart = value;
        let newEnd = value;

        // Check merge with previous
        if (pos > 0 && this.intervals[pos-1][1] + 1 >= value) {
            newStart = this.intervals[pos-1][0];
            pos--;
        }

        // Check merge with next intervals
        let mergeEnd = pos;
        while (mergeEnd < this.intervals.length && this.intervals[mergeEnd][0] <= newEnd + 1) {
            newEnd = Math.max(newEnd, this.intervals[mergeEnd][1]);
            mergeEnd++;
        }

        // Replace intervals
        this.intervals.splice(pos, mergeEnd - pos, [newStart, newEnd]);
    }

    getIntervals() {
        return [...this.intervals];
    }
}

function solution(operations, values) {
    const sr = new SummaryRanges();
    const results = [];

    for (let i = 0; i < operations.length; i++) {
        if (operations[i] === "SummaryRanges") {
            results.push(null);
        } else if (operations[i] === "addNum") {
            sr.addNum(values[i]);
            results.push(null);
        } else if (operations[i] === "getIntervals") {
            results.push(sr.getIntervals());
        }
    }

    return results;
}

