        } else {
            size += 1;
        }
    }

    // Second pass: work backwards
    for (int i = s.length() - 1; i >= 0; i--) {
        char c = s[i];
        k = k % size;
        if (k == 0 && isalpha(c)) {
            return string(1, c);
        }
        if (isdigit(c)) {
            size /= (c - '0');
        } else {
            size -= 1;
        }
    }

    return "";
}

int main() {
    string s;
    getline(cin, s);
    int k;
    cin >> k;
    string result = solution(s, k);
    cout << result << endl;
    return 0;
}

