        return key % BUCKETS;
    }

public:
    MyHashSet() {
        table.resize(BUCKETS);
    }

    void add(int key) {
        int bucket = hash(key);
        if (find(table[bucket].begin(), table[bucket].end(), key) == table[bucket].end()) {
            table[bucket].push_back(key);
        }
    }

    void remove(int key) {
        int bucket = hash(key);
        auto it = find(table[bucket].begin(), table[bucket].end(), key);
        if (it != table[bucket].end()) {
            table[bucket].erase(it);
        }
