#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <stdbool.h>

#define BUCKETS 1000

typedef struct Node {
    int key;
    struct Node* next;
} Node;

typedef struct {
    Node* table[BUCKETS];
} MyHashSet;

int hash(int key) {
    return key % BUCKETS;
}

MyHashSet* myHashSetCreate() {
    MyHashSet* obj = (MyHashSet*)malloc(sizeof(MyHashSet));
    for (int i = 0; i < BUCKETS; i++) {
        obj->table[i] = NULL;
    }
    return obj;
}

void myHashSetAdd(MyHashSet* obj, int key) {
    int bucket = hash(key);
    Node* current = obj->table[bucket];

    while (current) {
        if (current->key == key) return;
        current = current->next;
    }

    Node* newNode = (Node*)malloc(sizeof(Node));
    newNode->key = key;
    newNode->next = obj->table[bucket];
    obj->table[bucket] = newNode;
}

void myHashSetRemove(MyHashSet* obj, int key) {
    int bucket = hash(key);
    Node* current = obj->table[bucket];
    Node* prev = NULL;

    while (current) {
        if (current->key == key) {
            if (prev) {
                prev->next = current->next;
            } else {
                obj->table[bucket] = current->next;
            }
            free(current);
            return;
        }
        prev = current;
        current = current->next;
    }
}

bool myHashSetContains(MyHashSet* obj, int key) {
    int bucket = hash(key);
    Node* current = obj->table[bucket];

    while (current) {
        if (current->key == key) {
            return true;
        }
        current = current->next;
    }
    return false;
}

void myHashSetFree(MyHashSet* obj) {
    for (int i = 0; i < BUCKETS; i++) {
        Node* current = obj->table[i];
        while (current) {
            Node* temp = current;
            current = current->next;
            free(temp);
        }
    }
    free(obj);
}

