    // Simple test - in real implementation would parse JSON input
    MyHashSet* hashset = myHashSetCreate();

    myHashSetAdd(hashset, 1);
    myHashSetAdd(hashset, 2);
    printf("[null,null,null,%s,false,null,true,null,false]\n", 
           myHashSetContains(hashset, 1) ? "true" : "false");

    myHashSetFree(hashset);
    return 0;
}

