import java.util.*;
import java.io.*;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.JsonNode;

class Main {
    public static Object solution(Object obj1, Object obj2) {
        ObjectMapper mapper = new ObjectMapper();
        JsonNode node1 = mapper.valueToTree(obj1);
        JsonNode node2 = mapper.valueToTree(obj2);
        Object result = compareObjects(node1, node2, mapper);
        return result != null ? result : new HashMap<String, Object>();
    }

    private static Object compareObjects(JsonNode o1, JsonNode o2, ObjectMapper mapper) {
        // Quick equality check
        if (o1.equals(o2)) {
            return null;
        }

        // Handle null cases
        if (o1.isNull() || o2.isNull()) {
            return Arrays.asList(
                mapper.convertValue(o1, Object.class),
                mapper.convertValue(o2, Object.class)
            );
        }

        // Type check for primitives
        boolean o1IsContainer = o1.isContainerNode();
        boolean o2IsContainer = o2.isContainerNode();

        if (!o1IsContainer || !o2IsContainer) {
            return Arrays.asList(
                mapper.convertValue(o1, Object.class),
                mapper.convertValue(o2, Object.class)
            );
        }

        // Type mismatch (object vs array)
        if (o1.isArray() != o2.isArray()) {
            return Arrays.asList(
                mapper.convertValue(o1, Object.class),
                mapper.convertValue(o2, Object.class)
            );
        }

        Map<String, Object> differences = new HashMap<>();

        if (o1.isArray()) {
            // Compare arrays by index
            int minLength = Math.min(o1.size(), o2.size());
            for (int i = 0; i < minLength; i++) {
                Object diff = compareObjects(o1.get(i), o2.get(i), mapper);
                if (diff != null) {
                    differences.put(String.valueOf(i), diff);
                }
            }
        } else {
            // Only compare keys that exist in both objects
            Iterator<String> keys = o1.fieldNames();
            while (keys.hasNext()) {
                String key = keys.next();
                if (o2.has(key)) {
                    Object diff = compareObjects(o1.get(key), o2.get(key), mapper);
                    if diff != null) {
                        differences.put(key, diff);
                    }
                }
            }
        }

        return differences.isEmpty() ? null : differences;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        ObjectMapper mapper = new ObjectMapper();
        Object obj1 = mapper.readValue(br.readLine(), Object.class);
        Object obj2 = mapper.readValue(br.readLine(), Object.class);
        Object result = solution(obj1, obj2);
        System.out.println(mapper.writeValueAsString(result));
    }
}

import java.util.*;
import java.io.*;

class Main {
    public static int solution(int n, int[][] edges) {
        // Build adjacency list
        List<Integer>[] adj = new List[n + 1];
        for (int i = 0; i <= n; i++) {
            adj[i] = new ArrayList<>();
        }
        for (int[] edge : edges) {
            adj[edge[0]].add(edge[1]);
            adj[edge[1]].add(edge[0]);
        }

        boolean[] visited = new boolean[n + 1];
        int totalGroups = 0;

        // Process each component
        for (int start = 1; start <= n; start++) {
            if (visited[start]) continue;

            List<Integer> component = new ArrayList<>();
            Queue<Integer> queue = new LinkedList<>();
            queue.offer(start);
            visited[start] = true;

            while (!queue.isEmpty()) {
                int node = queue.poll();
                component.add(node);
                for (int neighbor : adj[node]) {
                    if (!visited[neighbor]) {
                        visited[neighbor] = true;
                        queue.offer(neighbor);
                    }
                }
            }

            if (!isBipartite(component, adj)) {
                return -1;
            }

            int maxDist = 0;
            Set<Integer> componentSet = new HashSet<>(component);
            for (int node : component) {
                int dist = bfsMaxDistance(node, adj, componentSet);
                maxDist = Math.max(maxDist, dist);
            }

            totalGroups = Math.max(totalGroups, maxDist + 1);
        }

        return totalGroups;
    }

    private static boolean isBipartite(List<Integer> component, List<Integer>[] adj) {
        Map<Integer, Integer> color = new HashMap<>();
        Queue<Integer> queue = new LinkedList<>();
        queue.offer(component.get(0));
        color.put(component.get(0), 0);

        while (!queue.isEmpty()) {
            int node = queue.poll();
            for (int neighbor : adj[node]) {
                if (color.containsKey(neighbor)) {
                    if (color.get(neighbor).equals(color.get(node))) {
                        return false;
                    }
                } else {
                    color.put(neighbor, 1 - color.get(node));
                    queue.offer(neighbor);
                }
            }
        }
        return true;
    }

    private static int bfsMaxDistance(int start, List<Integer>[] adj, Set<Integer> componentSet) {
        Queue<int[]> queue = new LinkedList<>();
        Set<Integer> visited = new HashSet<>();
        queue.offer(new int[]{start, 0});
        visited.add(start);
        int maxDist = 0;

        while (!queue.isEmpty()) {
            int[] curr = queue.poll();
            int node = curr[0], dist = curr[1];
            maxDist = Math.max(maxDist, dist);

            for (int neighbor : adj[node]) {
                if (!visited.contains(neighbor) && componentSet.contains(neighbor)) {
                    visited.add(neighbor);
                    queue.offer(new int[]{neighbor, dist + 1});
                }
            }
        }

        return maxDist;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int n = Integer.parseInt(br.readLine().trim());
        String edgesStr = br.readLine().trim();

        // Parse edges array
        List<int[]> edgesList = new ArrayList<>();
        if (edgesStr.length() > 2) {
            edgesStr = edgesStr.substring(1, edgesStr.length() - 1);
            if (!edgesStr.trim().isEmpty()) {
                String[] parts = edgesStr.split("],\\[");
                for (int i = 0; i < parts.length; i++) {
                    String part = parts[i].replace("[", "").replace("]", "");
                    String[] nums = part.split(",");
                    edgesList.add(new int[]{Integer.parseInt(nums[0].trim()), Integer.parseInt(nums[1].trim())});
                }
            }
        }

        int[][] edges = edgesList.toArray(new int[edgesList.size()][]);
        int result = solution(n, edges);
        System.out.println(result);
    }
}

import java.util.*;
