class Node {
    public int val;
    public List<Node> children;

    public Node() {
        children = new ArrayList<>();
    }

    public Node(int _val) {
        val = _val;
        children = new ArrayList<>();
    }

    public Node(int _val, List<Node> _children) {
        val = _val;
        children = _children;
    }
}

class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
    TreeNode(int x) { val = x; }
}

class Codec {
    public TreeNode encode(Node root) {
        if (root == null) return null;

        TreeNode binaryRoot = new TreeNode(root.val);

        if (!root.children.isEmpty()) {
            binaryRoot.left = encode(root.children.get(0));

            TreeNode current = binaryRoot.left;
            for (int i = 1; i < root.children.size(); i++) {
                current.right = encode(root.children.get(i));
                current = current.right;
            }
        }

        return binaryRoot;
    }

    public Node decode(TreeNode data) {
        if (data == null) return null;

        Node naryRoot = new Node(data.val);

        if (data.left != null) {
            TreeNode child = data.left;
            while (child != null) {
                naryRoot.children.add(decode(child));
                child = child.right;
            }
        }

        return naryRoot;
    }
}

class Main {
    public static List<Object> solution(Node root) {
        Codec codec = new Codec();
        TreeNode encoded = codec.encode(root);
        Node decoded = codec.decode(encoded);

        List<Object> result = new ArrayList<>();
        if (decoded == null) return result;

        Queue<Node> queue = new LinkedList<>();
        queue.offer(decoded);

        while (!queue.isEmpty()) {
            Node node = queue.poll();
            result.add(node.val);

            if (!node.children.isEmpty()) {
                queue.addAll(node.children);
                result.add(null);
            }
        }

        while (!result.isEmpty() && result.get(result.size() - 1) == null) {
            result.remove(result.size() - 1);
        }

        return result;
    }

