#include <vector>
#include <algorithm>
#include <string>
#include <sstream>
using namespace std;

vector<int> solution(vector<vector<int>>& restaurants, int veganFriendly, int maxPrice, int maxDistance) {
    vector<pair<int, int>> filtered;

    // Filter restaurants
    for (auto& restaurant : restaurants) {
        int id = restaurant[0], rating = restaurant[1], vegan = restaurant[2];
        int price = restaurant[3], distance = restaurant[4];

        if (veganFriendly == 1 && vegan == 0) continue;
        if (price > maxPrice || distance > maxDistance) continue;

        filtered.push_back({id, rating});
    }

    // Sort by rating desc, then by id desc
    sort(filtered.begin(), filtered.end(), [](const pair<int, int>& a, const pair<int, int>& b) {
        if (b.second != a.second) return a.second > b.second; // rating desc
        return a.first > b.first; // id desc
    });

    vector<int> result;
    for (auto& p : filtered) {
        result.push_back(p.first);
    }
    return result;
}

int main() {
    string line;
    getline(cin, line);

    vector<vector<int>> restaurants;
    line = line.substr(1, line.length() - 2);

    stringstream ss(line);
    string token;
    while (getline(ss, token, ']')) {
        if (token.empty() || token == ",") continue;
        if (token[0] == ',') token = token.substr(1);
        if (token[0] == '[') token = token.substr(1);

        vector<int> restaurant(5);
        stringstream nums(token);
        string num;
        int i = 0;
        while (getline(nums, num, ',') && i < 5) {
            restaurant[i++] = stoi(num);
        }
        if (i == 5) restaurants.push_back(restaurant);
    }

    int veganFriendly, maxPrice, maxDistance;
    cin >> veganFriendly >> maxPrice >> maxDistance;

    vector<int> result = solution(restaurants, veganFriendly, maxPrice, maxDistance);
    cout << "[";
    for (int i = 0; i < result.size(); i++) {
        if (i > 0) cout << ",";
        cout << result[i];
    }
    cout << "]" << endl;

    return 0;
}

