        List<int[]> filtered = new ArrayList<>();

        // Filter restaurants
        for (int[] restaurant : restaurants) {
            int id = restaurant[0], rating = restaurant[1], vegan = restaurant[2];
            int price = restaurant[3], distance = restaurant[4];

            if (veganFriendly == 1 && vegan == 0) continue;
            if (price > maxPrice || distance > maxDistance) continue;

            filtered.add(new int[]{id, rating});
        }

        // Sort by rating desc, then by id desc
        filtered.sort((a, b) -> {
            if (b[1] != a[1]) return b[1] - a[1]; // rating desc
            return b[0] - a[0]; // id desc
        });

        int[] result = new int[filtered.size()];
        for (int i = 0; i < filtered.size(); i++) {
            result[i] = filtered.get(i)[0];
        }
        return result;
    }

