#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    int id;
    int rating;
} FilteredRestaurant;

int compare(const void* a, const void* b) {
    FilteredRestaurant* ra = (FilteredRestaurant*)a;
    FilteredRestaurant* rb = (FilteredRestaurant*)b;

    if (rb->rating != ra->rating) {
        return rb->rating - ra->rating; // rating desc
    }
    return rb->id - ra->id; // id desc
}

int* solution(int restaurants[][5], int restaurantsSize, int veganFriendly, int maxPrice, int maxDistance, int* returnSize) {
    FilteredRestaurant* filtered = (FilteredRestaurant*)malloc(restaurantsSize * sizeof(FilteredRestaurant));
    int filteredCount = 0;

    // Filter restaurants
    for (int i = 0; i < restaurantsSize; i++) {
        int id = restaurants[i][0], rating = restaurants[i][1], vegan = restaurants[i][2];
        int price = restaurants[i][3], distance = restaurants[i][4];

        if (veganFriendly == 1 && vegan == 0) continue;
        if (price > maxPrice || distance > maxDistance) continue;

        filtered[filteredCount].id = id;
        filtered[filteredCount].rating = rating;
        filteredCount++;
    }

    // Sort using built-in qsort
    qsort(filtered, filteredCount, sizeof(FilteredRestaurant), compare);

    int* result = (int*)malloc(filteredCount * sizeof(int));
    for (int i = 0; i < filteredCount; i++) {
        result[i] = filtered[i].id;
    }

    *returnSize = filteredCount;
    free(filtered);
    return result;
}

int main() {
    char line[10000];
    fgets(line, sizeof(line), stdin);

    // Parse restaurants array
    int restaurants[10000][5];
    int restaurantsSize = 0;

    char* token = strtok(line, "[");
    token = strtok(NULL, "]");

    while (token != NULL) {
        if (strlen(token) > 2) {
            int nums[5];
            int count = 0;
            char* numToken = strtok(token, ",");
            while (numToken != NULL && count < 5) {
                nums[count++] = atoi(numToken);
                numToken = strtok(NULL, ",");
            }
            if (count == 5) {
                for (int i = 0; i < 5; i++) {
                    restaurants[restaurantsSize][i] = nums[i];
                }
                restaurantsSize++;
            }
        }
        token = strtok(NULL, "]");
    }

    int veganFriendly, maxPrice, maxDistance;
    scanf("%d %d %d", &veganFriendly, &maxPrice, &maxDistance);

    int returnSize;
    int* result = solution(restaurants, restaurantsSize, veganFriendly, maxPrice, maxDistance, &returnSize);

    printf("[");
    for (int i = 0; i < returnSize; i++) {
        if (i > 0) printf(",");
        printf("%d", result[i]);
    }
    printf("]\n");

    free(result);
    return 0;
}

