    int n = filtered.size();
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n - i - 1; j++) {
            if (filtered[j].second < filtered[j + 1].second || 
                (filtered[j].second == filtered[j + 1].second && filtered[j].first < filtered[j + 1].first)) {
                swap(filtered[j], filtered[j + 1]);
            }
        }
    }

    vector<int> result;
    for (auto& p : filtered) {
        result.push_back(p.first);
    }
    return result;
}

