package main

import (
    "bufio"
    "fmt"
    "math"
    "os"
    "strconv"
    "strings"
)

func getPalindrome(prefix string, isOdd bool) string {
    suffix := reverse(prefix)
    if isOdd {
        suffix = suffix[1:]
    }
    return prefix + suffix
}

func reverse(s string) string {
    runes := []rune(s)
    for i, j := 0, len(runes)-1; i < j; i, j = i+1, j-1 {
        runes[i], runes[j] = runes[j], runes[i]
    }
    return string(runes)
}

func solution(n string) string {
    length := len(n)

    // Handle single digit
    if length == 1 {
        digit, _ := strconv.Atoi(n)
        if digit == 0 {
            return "1"
        }
        return strconv.Itoa(digit - 1)
    }

    candidates := make(map[string]bool)

    // Candidate 1: 999...999 (one digit less)
    candidates[strings.Repeat("9", length-1)] = true

    // Candidate 2: 100...001 (one digit more)
    candidates["1"+strings.Repeat("0", length-1)+"1"] = true

    // Get the middle part for mirroring
    isOdd := length%2 == 1
    midEnd := length/2
    if isOdd {
        midEnd++
    }
    prefix := n[:midEnd]

    // Candidate 3: Mirror current prefix
    palin := getPalindrome(prefix, isOdd)
    if palin != n {
        candidates[palin] = true
    }

    // Candidate 4: Increment prefix and mirror
    prefixNum, _ := strconv.ParseInt(prefix, 10, 64)
    nextPrefix := strconv.FormatInt(prefixNum+1, 10)
    if len(nextPrefix) == len(prefix) {
        candidates[getPalindrome(nextPrefix, isOdd)] = true
    }

    // Candidate 5: Decrement prefix and mirror
    if prefixNum > 0 {
        prevPrefix := fmt.Sprintf("%0*d", len(prefix), prefixNum-1)
        candidates[getPalindrome(prevPrefix, isOdd)] = true
    }

    // Find closest
    num, _ := strconv.ParseInt(n, 10, 64)
    minDiff := int64(math.MaxInt64)
    result := ""

    for candidate := range candidates {
        if candidate != "" && candidate != n {
            candidateNum, _ := strconv.ParseInt(candidate, 10, 64)
            diff := candidateNum - num
            if diff < 0 {
                diff = -diff
            }
            if diff < minDiff || (diff == minDiff && (result == "" || candidateNum < strconv.ParseInt(result, 10, 64))) {
                minDiff = diff
                result = candidate
            }
        }
    }

    return result
}

func main() {
    reader := bufio.NewReader(os.Stdin)
    n, _ := reader.ReadString('\n')
    n = strings.TrimSpace(n)
    fmt.Println(solution(n))
}

