import java.util.*;
import java.io.*;

class Main {
    public static int solution(int n, int[][] pick) {
        int winners = 0;
        for (int player = 0; player < n; player++) {
            Map<Integer, Integer> colorCount = new HashMap<>();
            for (int[] p : pick) {
                if (p[0] == player) {
                    colorCount.put(p[1], colorCount.getOrDefault(p[1], 0) + 1);
                }
            }
            int maxCount = colorCount.values().stream().mapToInt(Integer::intValue).max().orElse(0);
            if (maxCount > player) {
                winners++;
            }
        }
        return winners;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int n = Integer.parseInt(br.readLine().trim());
        String pickStr = br.readLine().trim();
        pickStr = pickStr.substring(1, pickStr.length() - 1);
        String[] pairs = pickStr.split("],\[");
        int[][] pick = new int[pairs.length][2];
        for (int i = 0; i < pairs.length; i++) {
            String pair = pairs[i].replace("[", "").replace("]", "");
            String[] nums = pair.split(",");
            pick[i][0] = Integer.parseInt(nums[0]);
            pick[i][1] = Integer.parseInt(nums[1]);
        }
        System.out.println(solution(n, pick));
    }
}

