#include <iostream>
#include <vector>
#include <map>
#include <sstream>
#include <string>
#include <regex>
using namespace std;

int solution(int n, vector<vector<int>>& pick) {
    int winners = 0;
    for (int player = 0; player < n; player++) {
        map<int, int> colorCount;
        for (auto& p : pick) {
            if (p[0] == player) {
                colorCount[p[1]]++;
            }
        }
        int maxCount = 0;
        for (auto& pair : colorCount) {
            maxCount = max(maxCount, pair.second);
        }
        if (maxCount > player) {
            winners++;
        }
    }
    return winners;
}

int main() {
    int n;
    cin >> n;
    cin.ignore();

    string line;
    getline(cin, line);

    vector<vector<int>> pick;
    line = line.substr(1, line.length() - 2);

    regex pairRegex("\\[(\\d+),(\\d+)\\]");
    sregex_iterator iter(line.begin(), line.end(), pairRegex);
    sregex_iterator end;

    while (iter != end) {
        smatch match = *iter;
        vector<int> pair = {stoi(match[1]), stoi(match[2])};
        pick.push_back(pair);
        ++iter;
    }

    cout << solution(n, pick) << endl;
    return 0;
}

