package main

import (
    "bufio"
    "encoding/json"
    "fmt"
    "os"
    "strconv"
    "strings"
)

func differsByOneBit(a, b int) bool {
    diff := a ^ b
    return diff > 0 && (diff&(diff-1)) == 0
}

func backtrack(result *[]int, used map[int]bool, target int) bool {
    if len(*result) == target {
        return differsByOneBit((*result)[len(*result)-1], (*result)[0])
    }

    current := (*result)[len(*result)-1]
    for nextNum := 0; nextNum < target; nextNum++ {
        if !used[nextNum] && differsByOneBit(current, nextNum) {
            *result = append(*result, nextNum)
            used[nextNum] = true
            if backtrack(result, used, target) {
                return true
            }
            *result = (*result)[:len(*result)-1]
            delete(used, nextNum)
        }
    }
    return false
}

func solution(n int) []int {
    if n == 0 {
        return []int{0}
    }

    target := 1 << n
    result := []int{0}
    used := map[int]bool{0: true}

    backtrack(&result, used, target)
    return result
}

func main() {
    reader := bufio.NewReader(os.Stdin)
    line, _ := reader.ReadString('\n')
    n, _ := strconv.Atoi(strings.TrimSpace(line))

    result := solution(n)
    jsonResult, _ := json.Marshal(result)
    fmt.Println(string(jsonResult))
}

