import java.util.*;
import java.io.*;

class Main {
    public static int solution(int[] arr, int k) {
        if (arr.length == 0 || k == 0) return 0;

        final int MOD = 1000000007;
        int n = arr.length;

        if (k == 1) {
            long maxSum = 0;
            long currentSum = 0;
            for (int num : arr) {
                currentSum = Math.max(0, currentSum + num);
                maxSum = Math.max(maxSum, currentSum);
            }
            return (int)(maxSum % MOD);
        }

        // Find max subarray in single array
        long maxKadane = 0;
        long currentSum = 0;
        for (int num : arr) {
            currentSum = Math.max(0, currentSum + num);
            maxKadane = Math.max(maxKadane, currentSum);
        }

        // Find max prefix sum
        long maxPrefix = 0;
        currentSum = 0;
        for (int num : arr) {
            currentSum += num;
            maxPrefix = Math.max(maxPrefix, currentSum);
        }

        // Find max suffix sum
        long maxSuffix = 0;
        currentSum = 0;
        for (int i = n - 1; i >= 0; i--) {
            currentSum += arr[i];
            maxSuffix = Math.max(maxSuffix, currentSum);
        }

        long totalSum = 0;
        for (int num : arr) totalSum += num;

        long result = Math.max(maxKadane, maxPrefix + maxSuffix);

        if (k > 2 && totalSum > 0) {
            long middleContribution = (long)(k - 2) * totalSum;
            result = Math.max(result, maxPrefix + middleContribution + maxSuffix);
        }

        return (int)(result % MOD);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String[] arrStr = br.readLine().trim().replace("[", "").replace("]", "").split(",");
        int[] arr = new int[arrStr.length];
        for (int i = 0; i < arrStr.length; i++) {
            arr[i] = Integer.parseInt(arrStr[i].trim());
        }
        int k = Integer.parseInt(br.readLine().trim());
        System.out.println(solution(arr, k));
    }
}

