def largestPathValue(colors, edges):
    from collections import defaultdict, deque

    n = len(colors)
    graph = defaultdict(list)
    reverse_graph = defaultdict(list)
    in_degree = [0] * n

    # Build graph and reverse graph
    for a, b in edges:
        graph[a].append(b)
        reverse_graph[b].append(a)
        in_degree[b] += 1

    # Topological sort using Kahn's algorithm
    queue = deque([i for i in range(n) if in_degree[i] == 0])
    topo_order = []

    while queue:
        node = queue.popleft()
        topo_order.append(node)

        for neighbor in graph[node]:
            in_degree[neighbor] -= 1
            if in_degree[neighbor] == 0:
                queue.append(neighbor)

    # Cycle detection
    if len(topo_order) != n:
        return -1

    # DP: dp[node][color] = max count of color in paths ending at node
    dp = [[0] * 26 for _ in range(n)]

    # Process nodes in topological order
    for node in topo_order:
        # Current node contributes 1 to its own color
        dp[node][ord(colors[node]) - ord('a')] = 1

        # Update from all incoming edges
        for prev in reverse_graph[node]:
            for color in range(26):
                if color == ord(colors[node]) - ord('a'):
                    dp[node][color] = max(dp[node][color], dp[prev][color] + 1)
                else:
                    dp[node][color] = max(dp[node][color], dp[prev][color])

    # Find maximum value across all nodes and colors
    return max(max(row) for row in dp)

