#include <vector>
#include <queue>
#include <algorithm>
using namespace std;

class Solution {
public:
    int largestPathValue(string colors, vector<vector<int>>& edges) {
        int n = colors.length();
        vector<vector<int>> graph(n);
        vector<vector<int>> reverseGraph(n);
        vector<int> inDegree(n, 0);

        // Build graph and reverse graph
        for (auto& edge : edges) {
            graph[edge[0]].push_back(edge[1]);
            reverseGraph[edge[1]].push_back(edge[0]);
            inDegree[edge[1]]++;
        }

        // Topological sort
        queue<int> q;
        for (int i = 0; i < n; i++) {
            if (inDegree[i] == 0) {
                q.push(i);
            }
        }

        vector<int> topoOrder;
        while (!q.empty()) {
            int node = q.front();
            q.pop();
            topoOrder.push_back(node);

            for (int neighbor : graph[node]) {
                inDegree[neighbor]--;
                if (inDegree[neighbor] == 0) {
                    q.push(neighbor);
