import java.util.*;

class Solution {
    public int largestPathValue(String colors, int[][] edges) {
        int n = colors.length();
        List<List<Integer>> graph = new ArrayList<>();
        List<List<Integer>> reverseGraph = new ArrayList<>();
        int[] inDegree = new int[n];

        for (int i = 0; i < n; i++) {
            graph.add(new ArrayList<>());
            reverseGraph.add(new ArrayList<>());
        }

        // Build graph and reverse graph
        for (int[] edge : edges) {
            graph.get(edge[0]).add(edge[1]);
            reverseGraph.get(edge[1]).add(edge[0]);
            inDegree[edge[1]]++;
        }

        // Topological sort
        Queue<Integer> queue = new LinkedList<>();
        for (int i = 0; i < n; i++) {
            if (inDegree[i] == 0) {
                queue.offer(i);
            }
        }

        List<Integer> topoOrder = new ArrayList<>();
        while (!queue.isEmpty()) {
            int node = queue.poll();
            topoOrder.add(node);

            for (int neighbor : graph.get(node)) {
                inDegree[neighbor]--;
                if (inDegree[neighbor] == 0) {
                    queue.offer(neighbor);
                }
            }
        }

        if (topoOrder.size() != n) {
            return -1; // Cycle detected
        }

        // DP
        int[][] dp = new int[n][26];

        for (int node : topoOrder) {
            int colorIdx = colors.charAt(node) - 'a';
            dp[node][colorIdx] = 1;

            // Update from predecessors
            for (int prev : reverseGraph.get(node)) {
                for (int color = 0; color < 26; color++) {
                    if (color == colorIdx) {
                        dp[node][color] = Math.max(dp[node][color], dp[prev][color] + 1);
                    } else {
                        dp[node][color] = Math.max(dp[node][color], dp[prev][color]);
                    }
                }
            }
        }

        int maxValue = 0;
        for (int i = 0; i < n; i++) {
            for (int j = 0; j < 26; j++) {
                maxValue = Math.max(maxValue, dp[i][j]);
            }
        }

        return maxValue;
    }
}

