int largestPathValue(char* colors, int** edges, int edgesSize, int* edgesColSize) {
    int n = strlen(colors);

    // Build adjacency lists
    int** graph = (int**)malloc(n * sizeof(int*));
    int** reverseGraph = (int**)malloc(n * sizeof(int*));
    int* graphSizes = (int*)calloc(n, sizeof(int));
    int* reverseGraphSizes = (int*)calloc(n, sizeof(int));
    int* inDegree = (int*)calloc(n, sizeof(int));

    // Count edges
    for (int i = 0; i < edgesSize; i++) {
        graphSizes[edges[i][0]]++;
        reverseGraphSizes[edges[i][1]]++;
        inDegree[edges[i][1]]++;
    }

    // Allocate memory
    for (int i = 0; i < n; i++) {
        graph[i] = (int*)malloc(graphSizes[i] * sizeof(int));
        reverseGraph[i] = (int*)malloc(reverseGraphSizes[i] * sizeof(int));
        graphSizes[i] = 0;
        reverseGraphSizes[i] = 0;
    }

    // Fill adjacency lists
    for (int i = 0; i < edgesSize; i++) {
        graph[edges[i][0]][graphSizes[edges[i][0]]++] = edges[i][1];
        reverseGraph[edges[i][1]][reverseGraphSizes[edges[i][1]]++] = edges[i][0];
    }

    // Topological sort
    int* queue = (int*)malloc(n * sizeof(int));
    int front = 0, rear = 0;

    for (int i = 0; i < n; i++) {
        if (inDegree[i] == 0) {
            queue[rear++] = i;
        }
    }

    int* topoOrder = (int*)malloc(n * sizeof(int));
    int topoCount = 0;

    while (front < rear) {
        int node = queue[front++];
        topoOrder[topoCount++] = node;

        for (int i = 0; i < graphSizes[node]; i++) {
            int neighbor = graph[node][i];
            inDegree[neighbor]--;
            if (inDegree[neighbor] == 0) {
                queue[rear++] = neighbor;
            }
        }
    }

    if (topoCount != n) {
        // Cleanup and return
        for (int i = 0; i < n; i++) {
            free(graph[i]);
            free(reverseGraph[i]);
        }
        free(graph);
        free(reverseGraph);
        free(graphSizes);
        free(reverseGraphSizes);
        free(inDegree);
        free(queue);
        free(topoOrder);
        return -1;
    }

    // DP
    int** dp = (int**)malloc(n * sizeof(int*));
    for (int i = 0; i < n; i++) {
        dp[i] = (int*)calloc(26, sizeof(int));
    }

    for (int t = 0; t < topoCount; t++) {
        int node = topoOrder[t];
        int colorIdx = colors[node] - 'a';
        dp[node][colorIdx] = 1;

        // Update from predecessors
        for (int i = 0; i < reverseGraphSizes[node]; i++) {
            int prev = reverseGraph[node][i];
            for (int color = 0; color < 26; color++) {
                int newVal = (color == colorIdx) ? dp[prev][color] + 1 : dp[prev][color];
                if (newVal > dp[node][color]) {
                    dp[node][color] = newVal;
                }
            }
        }
    }

    int maxValue = 0;
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < 26; j++) {
            if (dp[i][j] > maxValue) {
                maxValue = dp[i][j];
            }
        }
    }

    // Cleanup
    for (int i = 0; i < n; i++) {
        free(graph[i]);
        free(reverseGraph[i]);
        free(dp[i]);
    }
    free(graph);
    free(reverseGraph);
    free(graphSizes);
    free(reverseGraphSizes);
    free(inDegree);
    free(queue);
    free(topoOrder);
    free(dp);

    return maxValue;
}

