import (
    "container/list"
)

func largestPathValue(colors string, edges [][]int) int {
    n := len(colors)
    graph := make([][]int, n)
    reverseGraph := make([][]int, n)
    inDegree := make([]int, n)

    // Build graph and reverse graph
    for _, edge := range edges {
        graph[edge[0]] = append(graph[edge[0]], edge[1])
        reverseGraph[edge[1]] = append(reverseGraph[edge[1]], edge[0])
        inDegree[edge[1]]++
    }

    // Topological sort
    queue := list.New()
    for i := 0; i < n; i++ {
        if inDegree[i] == 0 {
            queue.PushBack(i)
        }
    }

    var topoOrder []int
    for queue.Len() > 0 {
        element := queue.Front()
        node := element.Value.(int)
        queue.Remove(element)
        topoOrder = append(topoOrder, node)

        for _, neighbor := range graph[node] {
            inDegree[neighbor]--
            if inDegree[neighbor] == 0 {
                queue.PushBack(neighbor)
            }
        }
    }

    if len(topoOrder) != n {
        return -1
    }

    // DP
    dp := make([][]int, n)
    for i := range dp {
        dp[i] = make([]int, 26)
    }

    for _, node := range topoOrder {
        colorIdx := int(colors[node] - 'a')
        dp[node][colorIdx] = 1

        for _, prev := range reverseGraph[node] {
            for color := 0; color < 26; color++ {
                if color == colorIdx {
                    if dp[prev][color]+1 > dp[node][color] {
                        dp[node][color] = dp[prev][color] + 1
                    }
                } else {
                    if dp[prev][color] > dp[node][color] {
                        dp[node][color] = dp[prev][color]
                    }
                }
            }
        }
    }

    maxValue := 0
    for i := 0; i < n; i++ {
        for j := 0; j < 26; j++ {
            if dp[i][j] > maxValue {
                maxValue = dp[i][j]
            }
        }
    }

    return maxValue
}

