#include <stdio.h>
#include <stdlib.h>
#include <string.h>

#define MAX_SIZE 10000

struct HashNode {
    int key;
    int value;
    struct HashNode* next;
};

struct HashTable {
    struct HashNode* table[MAX_SIZE];
};

int hash(int key) {
    return (key + MAX_SIZE) % MAX_SIZE;
}

void put(struct HashTable* ht, int key, int value) {
    int index = hash(key);
    struct HashNode* node = ht->table[index];

    while (node != NULL) {
        if (node->key == key) {
            return; // Don't update if key exists
        }
        node = node->next;
    }

    struct HashNode* newNode = malloc(sizeof(struct HashNode));
    newNode->key = key;
    newNode->value = value;
    newNode->next = ht->table[index];
    ht->table[index] = newNode;
}

int get(struct HashTable* ht, int key, int* found) {
    int index = hash(key);
    struct HashNode* node = ht->table[index];

    while (node != NULL) {
        if (node->key == key) {
            *found = 1;
            return node->value;
        }
        node = node->next;
    }

    *found = 0;
    return -1;
}

int solution(int* hours, int n) {
    int prefixSum = 0;
    int maxLength = 0;
    struct HashTable ht = {0};

    for (int i = 0; i < n; i++) {
        // Transform: >8 hours = +1, ≤8 hours = -1
        prefixSum += hours[i] > 8 ? 1 : -1;

        // If prefix sum > 0, interval [0, i] is well-performing
        if (prefixSum > 0) {
            maxLength = i + 1;
        } else {
            // Look for earliest occurrence of (prefix_sum - 1)
            int target = prefixSum - 1;
            int found;
            int idx = get(&ht, target, &found);
            if (found) {
                int length = i - idx;
                if (length > maxLength) {
                    maxLength = length;
                }
            }

            // Store first occurrence of this prefix sum
            int dummy;
            get(&ht, prefixSum, &dummy);
            if (!dummy) {
                put(&ht, prefixSum, i);
            }
        }
    }

    return maxLength;
}

int main() {
    char line[10000];
    fgets(line, sizeof(line), stdin);

    int hours[1000];
    int n = 0;

    char* token = strtok(line, "[,]");
    while (token != NULL) {
        if (strlen(token) > 0 && token[0] != '\n') {
            hours[n++] = atoi(token);
        }
        token = strtok(NULL, "[,]");
    }

    int result = solution(hours, n);
    printf("%d\n", result);

    return 0;
}

