    if node == nil {
        return false
    }

    *path = append(*path, node)

    if node.Val == target {
        return true
    }

    if findPath(node.Left, target, path) || findPath(node.Right, target, path) {
        return true
    }

    *path = (*path)[:len(*path)-1]
    return false
}

func solution(root *TreeNode, p int, q int) int {
    var pathP []*TreeNode
    var pathQ []*TreeNode

    findPath(root, p, &pathP)
    findPath(root, q, &pathQ)

