    usedCount++;
}

char** solution(char** names, int namesSize, int* returnSize) {
    char** result = malloc(namesSize * sizeof(char*));
    *returnSize = 0;
    usedCount = 0;

    for (int i = 0; i < namesSize; i++) {
        if (!isUsed(names[i])) {
            result[*returnSize] = malloc(strlen(names[i]) + 1);
            strcpy(result[*returnSize], names[i]);
            addUsed(names[i]);
            (*returnSize)++;
        } else {
            int k = 1;
            char candidate[MAX_NAME_LEN];
            while (1) {
                sprintf(candidate, "%s(%d)", names[i], k);
                if (!isUsed(candidate)) {
                    result[*returnSize] = malloc(strlen(candidate) + 1);
                    strcpy(result[*returnSize], candidate);
                    addUsed(candidate);
                    (*returnSize)++;
                    break;
                }
                k++;
            }
        }
    }

    return result;
}

int main() {
    char line[10000];
    fgets(line, sizeof(line), stdin);

    char** names = malloc(1000 * sizeof(char*));
    int namesSize = 0;

    char* token = strtok(line, "[]\",\n");
    while (token != NULL) {
        if (strlen(token) > 0 && strcmp(token, " ") != 0) {
            names[namesSize] = malloc(strlen(token) + 1);
            strcpy(names[namesSize], token);
            namesSize++;
        }
        token = strtok(NULL, "[]\",\n");
    }

    int returnSize;
    char** result = solution(names, namesSize, &returnSize);

    printf("[");
    for (int i = 0; i < returnSize; i++) {
        printf("\"%s\"", result[i]);
        if (i < returnSize - 1) printf(",");
    }
    printf("]\n");

    return 0;
}

