func solution(rows, cols, rCenter, cCenter int) [][]int {
    // BFS approach for this problem - using level-order traversal by Manhattan distance
    result := [][]int{}
    visited := make([][]bool, rows)
    for i := range visited {
        visited[i] = make([]bool, cols)
    }

    // Use a slice that processes cells level by level based on Manhattan distance
    currentLevel := [][]int{{rCenter, cCenter}}
    visited[rCenter][cCenter] = true

    for len(currentLevel) > 0 {
        // Process all cells at current distance level
        nextLevel := [][]int{}
        for _, cell := range currentLevel {
            result = append(result, []int{cell[0], cell[1]})
        }

        // Find all unvisited cells at the next distance level
        for _, cell := range currentLevel {
            r, c := cell[0], cell[1]
            // Check all possible positions that could be at distance+1
            for nr := 0; nr < rows; nr++ {
                for nc := 0; nc < cols; nc++ {
                    if !visited[nr][nc] {
                        currDist := abs(r-rCenter) + abs(c-cCenter)
                        nextDist := abs(nr-rCenter) + abs(nc-cCenter)
                        if nextDist == currDist+1 {
                            visited[nr][nc] = true
                            nextLevel = append(nextLevel, []int{nr, nc})
                        }
                    }
                }
            }
        }

        // Remove duplicates
        seen := make(map[string]bool)
        uniqueNext := [][]int{}
        for _, cell := range nextLevel {
            key := fmt.Sprintf("%d,%d", cell[0], cell[1])
            if !seen[key] {
                seen[key] = true
                uniqueNext = append(uniqueNext, cell)
