typedef struct {
    int r, c;
} Cell;

int abs_val(int x) {
    return x < 0 ? -x : x;
}

int** solution(int rows, int cols, int rCenter, int cCenter, int* returnSize, int** returnColumnSizes) {
    // BFS approach for this problem - using level-order traversal by Manhattan distance
    *returnSize = rows * cols;
    *returnColumnSizes = malloc(*returnSize * sizeof(int));
    int** result = malloc(*returnSize * sizeof(int*));

    bool** visited = malloc(rows * sizeof(bool*));
    for (int i = 0; i < rows; i++) {
        visited[i] = calloc(cols, sizeof(bool));
    }

    Cell* currentLevel = malloc(rows * cols * sizeof(Cell));
    Cell* nextLevel = malloc(rows * cols * sizeof(Cell));
    int currentSize = 1;
    currentLevel[0] = (Cell){rCenter, cCenter};
    visited[rCenter][cCenter] = true;

    int resultIdx = 0;

    while (currentSize > 0) {
        // Process all cells at current distance level
        int nextSize = 0;
        for (int i = 0; i < currentSize; i++) {
            result[resultIdx] = malloc(2 * sizeof(int));
            result[resultIdx][0] = currentLevel[i].r;
            result[resultIdx][1] = currentLevel[i].c;
            (*returnColumnSizes)[resultIdx] = 2;
            resultIdx++;
        }

        // Find all unvisited cells at the next distance level
        for (int i = 0; i < currentSize; i++) {
            int r = currentLevel[i].r, c = currentLevel[i].c;
            // Check all possible positions that could be at distance+1
            for (int nr = 0; nr < rows; nr++) {
                for (int nc = 0; nc < cols; nc++) {
                    if (!visited[nr][nc]) {
                        int currDist = abs_val(r - rCenter) + abs_val(c - cCenter);
                        int nextDist = abs_val(nr - rCenter) + abs_val(nc - cCenter);
                        if (nextDist == currDist + 1) {
                            visited[nr][nc] = true;
                            nextLevel[nextSize++] = (Cell){nr, nc};
                        }
                    }
                }
            }
        }

        // Remove duplicates (simple approach for small matrices)
        int uniqueSize = 0;
        for (int i = 0; i < nextSize; i++) {
            bool duplicate = false;
            for (int j = 0; j < uniqueSize; j++) {
                if (currentLevel[j].r == nextLevel[i].r && currentLevel[j].c == nextLevel[i].c) {
                    duplicate = true;
                    break;
                }
            }
            if (!duplicate) {
                currentLevel[uniqueSize++] = nextLevel[i];
            }
        }
        currentSize = uniqueSize;
    }

    *returnSize = resultIdx;
    return result;
}

int main() {
    int rows, cols, rCenter, cCenter;
    scanf("%d %d %d %d", &rows, &cols, &rCenter, &cCenter);

    int returnSize;
    int* returnColumnSizes;
    int** result = solution(rows, cols, rCenter, cCenter, &returnSize, &returnColumnSizes);

    printf("[");
    for (int i = 0; i < returnSize; i++) {
        if (i > 0) printf(",");
        printf("[%d,%d]", result[i][0], result[i][1]);
    }
    printf("]\n");

    return 0;
}

