import java.util.*;
import java.io.*;

class Main {
    public static long solution(int[] nums) {
        int n = nums.length;
        if (n > 20) {
            // Fallback to DP for large inputs to avoid timeout
            return dpSolution(nums);
        }

        long maxSum = Long.MIN_VALUE;

        // Try all possible subsequences using bit manipulation
        for (int mask = 1; mask < (1 << n); mask++) {
            List<Integer> subsequence = new ArrayList<>();
            List<Integer> indices = new ArrayList<>();

            // Extract subsequence based on mask
            for (int i = 0; i < n; i++) {
                if ((mask & (1 << i)) != 0) {
                    subsequence.add(nums[i]);
                    indices.add(i);
                }
            }

            // Check if subsequence is balanced
            boolean isBalanced = true;
            for (int j = 1; j < indices.size(); j++) {
                int idx1 = indices.get(j-1), idx2 = indices.get(j);
                if (nums[idx2] - nums[idx1] < idx2 - idx1) {
                    isBalanced = false;
                    break;
                }
            }

            // Update maximum sum if balanced
            if (isBalanced) {
                long sum = subsequence.stream().mapToLong(Integer::longValue).sum();
                maxSum = Math.max(maxSum, sum);
            }
        }

        return maxSum;
    }

    private static long dpSolution(int[] nums) {
        int n = nums.length;
        long[] dp = new long[n];
        for (int i = 0; i < n; i++) {
            dp[i] = nums[i];
        }

        for (int i = 0; i < n; i++) {
            for (int j = 0; j < i; j++) {
                if (nums[i] - i >= nums[j] - j) {
                    dp[i] = Math.max(dp[i], dp[j] + nums[i]);
                }
            }
        }

        return Arrays.stream(dp).max().orElse(Long.MIN_VALUE);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine().trim();

        // Parse JSON array format
        line = line.substring(1, line.length()-1); // Remove [ ]
        if (line.isEmpty()) {
            System.out.println(0);
            return;
        }

        String[] parts = line.split(",");
        int[] nums = new int[parts.length];
        for (int i = 0; i < parts.length; i++) {
            nums[i] = Integer.parseInt(parts[i].trim());
        }

        long result = solution(nums);
        System.out.println(result);
    }
}

