def solution(s):
    def calculate_sum(n):
        if n == 0:
            return 0

        total = 0
        # For each i from 0 to n-1
        for i in range(n):
            # For each possible OR value from 0 to n-1
            for or_val in range(n):
                # Count how many (j,k) pairs give j|k = or_val
                count = 0
                for j in range(n):
                    for k in range(n):
                        if (j | k) == or_val:
                            count += 1
                total += i * or_val * count

        return total

    n = 1
    while calculate_sum(n) <= s:
        n += 1
    return n - 1

