function solution(graph, initial) {
    const n = graph.length;
    const initialSet = new Set(initial);
    let minInfected = Infinity;
    let result = initial[0];

    function dfs(node, visited, graphCopy) {
        if (visited[node]) return;
        visited[node] = true;
        for (let neighbor = 0; neighbor < n; neighbor++) {
            if (graphCopy[node][neighbor] === 1 && !visited[neighbor]) {
                dfs(neighbor, visited, graphCopy);
            }
        }
    }

    for (const removeNode of initial) {
        // Create graph copy without removeNode
        const graphCopy = graph.map(row => [...row]);
        for (let i = 0; i < n; i++) {
            graphCopy[removeNode][i] = 0;
            graphCopy[i][removeNode] = 0;
        }

        const visited = new Array(n).fill(false);
        visited[removeNode] = true; // Mark removed node as visited

        // Start infection from remaining initial nodes
        for (const startNode of initial) {
            if (startNode !== removeNode && !visited[startNode]) {
                dfs(startNode, visited, graphCopy);
            }
        }

        // Count infected nodes (excluding removed node)
        const infectedCount = visited.filter(v => v).length - 1; // -1 for removed node

        if (infectedCount < minInfected || (infectedCount === minInfected && removeNode < result)) {
            minInfected = infectedCount;
            result = removeNode;
        }
    }

    return result;
}

