import java.util.*;
import java.io.*;

class Main {
    public static int solution(int[][] graph, int[] initial) {
        int n = graph.length;
        Set<Integer> initialSet = new HashSet<>();
        for (int node : initial) initialSet.add(node);

        int minInfected = Integer.MAX_VALUE;
        int result = initial[0];

        for (int removeNode : initial) {
            // Create graph copy without removeNode
            int[][] graphCopy = new int[n][n];
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    graphCopy[i][j] = graph[i][j];
                }
            }
            for (int i = 0; i < n; i++) {
                graphCopy[removeNode][i] = 0;
                graphCopy[i][removeNode] = 0;
            }

            boolean[] visited = new boolean[n];
            visited[removeNode] = true;

            for (int startNode : initial) {
                if (startNode != removeNode && !visited[startNode]) {
                    dfs(startNode, visited, graphCopy);
                }
            }

            // Count infected nodes (excluding removed node)
            int infectedCount = 0;
            for (int i = 0; i < n; i++) {
                if (visited[i] && i != removeNode) infectedCount++;
            }

            if (infectedCount < minInfected || (infectedCount == minInfected && removeNode < result)) {
                minInfected = infectedCount;
                result = removeNode;
            }
        }

        return result;
    }

    private static void dfs(int node, boolean[] visited, int[][] graph) {
        if (visited[node]) return;
        visited[node] = true;
        for (int neighbor = 0; neighbor < graph.length; neighbor++) {
            if (graph[node][neighbor] == 1 && !visited[neighbor]) {
                dfs(neighbor, visited, graph);
            }
        }
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String[] graphStr = br.readLine().trim().replaceAll("[\\[\\]]", "").split("],\\[");
