        for (int i = 0; i < n; i++) {
            String[] row = graphStr[i].replaceAll("[\\[\\]]", "").split(",");
            for (int j = 0; j < row.length; j++) {
                graph[i][j] = Integer.parseInt(row[j].trim());
            }
