function solution(nums, p) {
    if (p === 0) return 0;

    const n = nums.length;
    let minMaxDiff = Infinity;

    // Generate all combinations of 2*p indices
    function getCombinations(arr, r) {
        const result = [];
        function backtrack(start, current) {
            if (current.length === r) {
                result.push([...current]);
                return;
            }
            for (let i = start; i < arr.length; i++) {
                current.push(arr[i]);
                backtrack(i + 1, current);
                current.pop();
            }
        }
        backtrack(0, []);
        return result;
    }

    function generatePairings(indices) {
        if (indices.length === 0) return [[]];
        if (indices.length === 2) return [[[indices[0], indices[1]]]];

        const result = [];
        const first = indices[0];
        for (let i = 1; i < indices.length; i++) {
            const pair = [first, indices[i]];
            const remaining = indices.slice(1, i).concat(indices.slice(i + 1));
            const subPairings = generatePairings(remaining);
            for (const subPairing of subPairings) {
                result.push([pair].concat(subPairing));
            }
        }
        return result;
    }

    const indices = Array.from({length: n}, (_, i) => i);
    const combinations = getCombinations(indices, 2 * p);

    for (const selectedIndices of combinations) {
        const pairings = generatePairings(selectedIndices);
        for (const pairing of pairings) {
            let maxDiff = 0;
            for (const [i, j] of pairing) {
                maxDiff = Math.max(maxDiff, Math.abs(nums[i] - nums[j]));
            }
            minMaxDiff = Math.min(minMaxDiff, maxDiff);
        }
    }

    return minMaxDiff;
}

