#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>

int compare(const void* a, const void* b) {
    return (*(int*)a - *(int*)b);
}

int canFormPairs(int* nums, int nums_size, int p, int maxDiff) {
    int pairs = 0;
    int i = 0;

    while (i < nums_size - 1) {
        if (nums[i + 1] - nums[i] <= maxDiff) {
            pairs++;
            i += 2;
            if (pairs >= p) return 1;
        } else {
            i++;
        }
    }

    return pairs >= p;
}

int solution(int* nums, int nums_size, int p) {
    if (p == 0) return 0;

    qsort(nums, nums_size, sizeof(int), compare);

    int left = 0;
    int right = nums[nums_size - 1] - nums[0];
    int result = right;

    while (left <= right) {
        int mid = left + (right - left) / 2;
        if (canFormPairs(nums, nums_size, p, mid)) {
            result = mid;
            right = mid - 1;
        } else {
            left = mid + 1;
        }
    }

    return result;
}

