            // Binary search for closest values
            let left = 0, right = candidates.length;
            while (left < right) {
                const mid = Math.floor((left + right) / 2);
                if (candidates[mid] < nums[i]) left = mid + 1;
                else right = mid;
            }

            // Check ceiling
            if (left < candidates.length) {
                minDiff = Math.min(minDiff, Math.abs(candidates[left] - nums[i]));
            }
            // Check floor
            if (left > 0) {
                minDiff = Math.min(minDiff, Math.abs(candidates[left-1] - nums[i]));
            }
        }

        // Insert current element in sorted order
        let pos = 0;
        while (pos < candidates.length && candidates[pos] < nums[i]) pos++;
        candidates.splice(pos, 0, nums[i]);
    }

    return minDiff;
}

