#include <iostream>
#include <vector>
#include <string>
#include <sstream>
#include <set>
#include <climits>
using namespace std;

int solution(vector<int>& nums, int x) {
    int n = nums.size();
    int minDiff = INT_MAX;
    multiset<int> candidates;

    for (int i = 0; i < n; i++) {
        if (i >= x) {
            auto it = candidates.lower_bound(nums[i]);

            // Check ceiling
            if (it != candidates.end()) {
                minDiff = min(minDiff, abs(*it - nums[i]));
            }

            // Check floor
            if (it != candidates.begin()) {
                --it;
                minDiff = min(minDiff, abs(*it - nums[i]));
            }
        }

        candidates.insert(nums[i]);
    }

    return minDiff;
}

