package main

import (
    "bufio"
    "encoding/json"
    "fmt"
    "os"
    "sort"
    "strconv"
    "strings"
)

func abs(a int) int {
    if a < 0 {
        return -a
    }
    return a
}

func min(a, b int) int {
    if a < b {
        return a
    }
    return b
}

func solution(nums []int, x int) int {
    n := len(nums)
    minDiff := 1<<31 - 1
    candidates := []int{}

    for i := 0; i < n; i++ {
        if i >= x {
            // Binary search for closest values
            pos := sort.SearchInts(candidates, nums[i])

            // Check ceiling
            if pos < len(candidates) {
                minDiff = min(minDiff, abs(candidates[pos]-nums[i]))
            }

            // Check floor
            if pos > 0 {
                minDiff = min(minDiff, abs(candidates[pos-1]-nums[i]))
            }
        }

        // Insert in sorted order
        pos := sort.SearchInts(candidates, nums[i])
        candidates = append(candidates, 0)
        copy(candidates[pos+1:], candidates[pos:])
        candidates[pos] = nums[i]
    }

    return minDiff
}

