#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>

int abs_val(int a) {
    return a < 0 ? -a : a;
}

int min_val(int a, int b) {
    return a < b ? a : b;
}

int binarySearch(int* arr, int size, int target) {
    int left = 0, right = size;
    while (left < right) {
        int mid = (left + right) / 2;
        if (arr[mid] < target) left = mid + 1;
        else right = mid;
    }
    return left;
}

int solution(int* nums, int numsSize, int x) {
    int minDiff = INT_MAX;
    int* candidates = (int*)malloc(numsSize * sizeof(int));
    int candidatesSize = 0;

    for (int i = 0; i < numsSize; i++) {
        if (i >= x) {
            int pos = binarySearch(candidates, candidatesSize, nums[i]);

            // Check ceiling
            if (pos < candidatesSize) {
                minDiff = min_val(minDiff, abs_val(candidates[pos] - nums[i]));
            }

            // Check floor
            if (pos > 0) {
                minDiff = min_val(minDiff, abs_val(candidates[pos-1] - nums[i]));
            }
        }

        // Insert in sorted order
        int pos = binarySearch(candidates, candidatesSize, nums[i]);
        for (int j = candidatesSize; j > pos; j--) {
            candidates[j] = candidates[j-1];
        }
        candidates[pos] = nums[i];
        candidatesSize++;
    }

    free(candidates);
    return minDiff;
}

