class Main {
    public static int solution(int[] forbidden, int a, int b, int x) {
        Set<Integer> forbiddenSet = new HashSet<>();
        for (int f : forbidden) forbiddenSet.add(f);

        Queue<int[]> queue = new LinkedList<>();
        Set<String> visited = new HashSet<>();

        queue.offer(new int[]{0, 0, 0}); // position, lastBackward(0/1), jumps
        visited.add("0,0");

        while (!queue.isEmpty()) {
            int[] curr = queue.poll();
            int pos = curr[0], lastBackward = curr[1], jumps = curr[2];

            if (pos == x) return jumps;

            // Forward jump
            int nextPos = pos + a;
            String state = nextPos + ",0";
            if (nextPos <= 6000 && !forbiddenSet.contains(nextPos) && !visited.contains(state)) {
                visited.add(state);
                queue.offer(new int[]{nextPos, 0, jumps + 1});
            }

            // Backward jump
            if (lastBackward == 0) {
                nextPos = pos - b;
                state = nextPos + ",1";
                if (nextPos >= 0 && !forbiddenSet.contains(nextPos) && !visited.contains(state)) {
                    visited.add(state);
                    queue.offer(new int[]{nextPos, 1, jumps + 1});
                }
            }
        }

        return -1;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine().trim();

        int[] forbidden;
        if (line.equals("[]")) {
            forbidden = new int[0];
        } else {
            String content = line.substring(1, line.length() - 1);
            if (content.trim().isEmpty()) {
                forbidden = new int[0];
            } else {
                String[] parts = content.split(",");
                forbidden = new int[parts.length];
                for (int i = 0; i < parts.length; i++) {
                    forbidden[i] = Integer.parseInt(parts[i].trim());
                }
            }
        }

        int a = Integer.parseInt(br.readLine().trim());
        int b = Integer.parseInt(br.readLine().trim());
        int x = Integer.parseInt(br.readLine().trim());

        System.out.println(solution(forbidden, a, b, x));
    }
}

