def solution(nums, pattern):
    n = len(nums)
    m = len(pattern)

    if n < m + 1:
        return 0

    # Convert nums to comparison array
    comparisons = []
    for i in range(n - 1):
        if nums[i + 1] > nums[i]:
            comparisons.append(1)
        elif nums[i + 1] == nums[i]:
            comparisons.append(0)
        else:
            comparisons.append(-1)

    # Use KMP algorithm for pattern matching
    def build_lps(pattern):
        lps = [0] * len(pattern)
        length = 0
        i = 1

        while i < len(pattern):
            if pattern[i] == pattern[length]:
                length += 1
                lps[i] = length
                i += 1
            else:
                if length != 0:
                    length = lps[length - 1]
                else:
                    lps[i] = 0
                    i += 1
        return lps

    def kmp_search(text, pattern):
        if not pattern:
            return 0

        lps = build_lps(pattern)
        count = 0
        i = j = 0

        while i < len(text):
            if text[i] == pattern[j]:
                i += 1
                j += 1

            if j == len(pattern):
                count += 1
                j = lps[j - 1]
            elif i < len(text) and text[i] != pattern[j]:
                if j != 0:
                    j = lps[j - 1]
                else:
                    i += 1

        return count

    return kmp_search(comparisons, pattern)

