    int* lps = (int*)malloc(m * sizeof(int));
    buildLPS(pattern, lps, m);

    int count = 0;
    int i = 0, j = 0;

    while (i < n) {
        if (text[i] == pattern[j]) {
            i++;
            j++;
        }

        if (j == m) {
            count++;
            j = lps[j - 1];
        } else if (i < n && text[i] != pattern[j]) {
            if (j != 0) {
                j = lps[j - 1];
            } else {
                i++;
            }
        }
    }

    free(lps);
    return count;
}

int solution(int* nums, int numsSize, int* pattern, int patternSize) {
    if (numsSize < patternSize + 1) {
        return 0;
    }

    // Convert nums to comparison array
    int* comparisons = (int*)malloc((numsSize - 1) * sizeof(int));

    for (int i = 0; i < numsSize - 1; i++) {
        if (nums[i + 1] > nums[i]) {
            comparisons[i] = 1;
        } else if (nums[i + 1] == nums[i]) {
            comparisons[i] = 0;
        } else {
            comparisons[i] = -1;
        }
    }

    int result = kmpSearch(comparisons, numsSize - 1, pattern, patternSize);

    free(comparisons);
    return result;
}

