class Main {
    public static int solution(String[] strs, int m, int n) {
        return backtrack(strs, 0, m, n);
    }

    private static int backtrack(String[] strs, int index, int zerosLeft, int onesLeft) {
        if (index == strs.length) {
            return 0;
        }

        // Skip current string
        int result = backtrack(strs, index + 1, zerosLeft, onesLeft);

        // Try including current string
        int[] count = countZerosOnes(strs[index]);
        int zeros = count[0], ones = count[1];
        if (zeros <= zerosLeft && ones <= onesLeft) {
            result = Math.max(result, 1 + backtrack(strs, index + 1, zerosLeft - zeros, onesLeft - ones));
        }

        return result;
    }

