import java.util.*;
import java.io.*;

class Main {
    public static int solution(String[] strs, int m, int n) {
        // dp[i][j] = max strings using at most i zeros and j ones
        int[][] dp = new int[m + 1][n + 1];

        for (String s : strs) {
            int[] count = countZerosOnes(s);
            int zeros = count[0], ones = count[1];

            // Update DP table backwards to avoid using updated values
            for (int i = m; i >= zeros; i--) {
                for (int j = n; j >= ones; j--) {
                    dp[i][j] = Math.max(dp[i][j], 1 + dp[i - zeros][j - ones]);
                }
            }
        }

        return dp[m][n];
    }

