import java.util.*;
import java.io.*;

class Main {
    public static boolean solution(int n, int[][] dislikes) {
        // Try all 2^n possible group assignments
        for (int mask = 0; mask < (1 << n); mask++) {
            boolean valid = true;
            // Check if this assignment satisfies all constraints
            for (int[] dislike : dislikes) {
                int a = dislike[0] - 1; // Convert to 0-indexed
                int b = dislike[1] - 1;
                // Check if both are in same group
                int aGroup = (mask >> a) & 1;
                int bGroup = (mask >> b) & 1;
                if (aGroup == bGroup) {
                    valid = false;
                    break;
                }
            }
            if (valid) return true;
        }
        return false;
    }

    public static void main(String[] args) throws Exception {
        Scanner sc = new Scanner(System.in);
        int n = sc.nextInt();
        sc.nextLine();
        String dislikesStr = sc.nextLine().trim();

        // Parse dislikes array
        dislikesStr = dislikesStr.substring(1, dislikesStr.length() - 1);
        if (dislikesStr.isEmpty()) {
            System.out.println(solution(n, new int[0][]));
            return;
        }

        String[] pairs = dislikesStr.split("],\\[");
        int[][] dislikes = new int[pairs.length][];

        for (int i = 0; i < pairs.length; i++) {
            String pair = pairs[i].replaceAll("\\[|\\]", "");
            String[] nums = pair.split(",");
            dislikes[i] = new int[]{Integer.parseInt(nums[0]), Integer.parseInt(nums[1])};
        }

        boolean result = solution(n, dislikes);
        System.out.println(result);
    }
}

