    public static int solution(int[] nums) {
        if (nums.length == 0) return 0;

        List<Integer> unique = new ArrayList<>();
        for (int i = 0; i < nums.length; i++) {
            boolean isDuplicate = false;
            for (int j = 0; j < i; j++) {
                if (nums[i] == nums[j]) {
                    isDuplicate = true;
                    break;
                }
            }
            if (!isDuplicate) {
                unique.add(nums[i]);
            }
        }

        // Copy unique elements back to original array
