#include <iostream>
#include <vector>
#include <string>
#include <sstream>
using namespace std;

struct ListNode {
    int val;
    ListNode* next;
    ListNode(int x) : val(x), next(nullptr) {}
};

ListNode* solution(ListNode* head, int k) {
    if (!head || !head->next || k == 0) {
        return head;
    }

    // Find length and make circular
    int length = 1;
    ListNode* tail = head;
    while (tail->next) {
        tail = tail->next;
        length++;
    }

    // Connect tail to head to make circular
    tail->next = head;

    // Calculate effective rotation
    k = k % length;
    if (k == 0) {
        tail->next = nullptr; // Break circle
        return head;
    }

    // Find the new tail (length - k - 1 steps from head)
    int stepsToNewTail = length - k;
    ListNode* newTail = head;
    for (int i = 0; i < stepsToNewTail - 1; i++) {
        newTail = newTail->next;
    }

    // New head is next to new tail
    ListNode* newHead = newTail->next;
    newTail->next = nullptr; // Break the circle

    return newHead;
}

ListNode* arrayToList(vector<int>& arr) {
    if (arr.empty()) return nullptr;
    ListNode* head = new ListNode(arr[0]);
    ListNode* curr = head;
    for (int i = 1; i < arr.size(); i++) {
        curr->next = new ListNode(arr[i]);
        curr = curr->next;
    }
    return head;
}

vector<int> listToArray(ListNode* head) {
    vector<int> result;
    while (head) {
        result.push_back(head->val);
        head = head->next;
    }
    return result;
}

vector<int> parseArray(string s) {
    vector<int> result;
    s = s.substr(1, s.length() - 2); // Remove brackets
    if (s.empty()) return result; // Handle empty array case
    stringstream ss(s);
    string item;
    while (getline(ss, item, ',')) {
        // Trim whitespace
        size_t start = item.find_first_not_of(" \t");
        size_t end = item.find_last_not_of(" \t");
        if (start != string::npos && end != string::npos) {
            item = item.substr(start, end - start + 1);
            result.push_back(stoi(item));
        }
    }
    return result;
}

int main() {
    string headStr;
    int k;
    getline(cin, headStr);
    cin >> k;

    vector<int> headArr = parseArray(headStr);
    ListNode* head = arrayToList(headArr);
    ListNode* result = solution(head, k);
    vector<int> resultArr = listToArray(result);

    cout << "[";
    for (int i = 0; i < resultArr.size(); i++) {
        cout << resultArr[i];
        if (i < resultArr.size() - 1) cout << ",";
    }
    cout << "]" << endl;

    return 0;
}

