def sellingWood(m, n, prices):
    # Create price lookup for direct sales
    price_map = {}
    for h, w, price in prices:
        price_map[(h, w)] = max(price_map.get((h, w), 0), price)

    def solve(h, w):
        if h <= 0 or w <= 0:
            return 0

        # Check if we can sell this piece directly
        max_profit = price_map.get((h, w), 0)

        # Try all horizontal cuts
        for cut in range(1, h):
            top = solve(cut, w)
            bottom = solve(h - cut, w)
            max_profit = max(max_profit, top + bottom)

        # Try all vertical cuts
        for cut in range(1, w):
            left = solve(h, cut)
            right = solve(h, w - cut)
            max_profit = max(max_profit, left + right)

        return max_profit

    return solve(m, n)

