function sellingWood(m, n, prices) {
    const priceMap = new Map();
    const memo = new Map();

    // Build price lookup
    for (const [h, w, price] of prices) {
        const key = `${h},${w}`;
        priceMap.set(key, Math.max(priceMap.get(key) || 0, price));
    }

    function solve(h, w) {
        if (h <= 0 || w <= 0) return 0;

        const key = `${h},${w}`;
        if (memo.has(key)) return memo.get(key);

        let maxProfit = priceMap.get(key) || 0;

        // Try horizontal cuts
        for (let cut = 1; cut < h; cut++) {
            const top = solve(cut, w);
            const bottom = solve(h - cut, w);
            maxProfit = Math.max(maxProfit, top + bottom);
        }

        // Try vertical cuts
        for (let cut = 1; cut < w; cut++) {
            const left = solve(h, cut);
            const right = solve(h, w - cut);
            maxProfit = Math.max(maxProfit, left + right);
        }

        memo.set(key, maxProfit);
        return maxProfit;
    }

    return solve(m, n);
}

