import java.util.*;

class Solution {
    public boolean areSentencesSimilarTwo(String[] sentence1, String[] sentence2, List<List<String>> similarPairs) {
        if (sentence1.length != sentence2.length) {
            return false;
        }

        // Build adjacency list
        Map<String, List<String>> graph = new HashMap<>();
        for (List<String> pair : similarPairs) {
            String word1 = pair.get(0), word2 = pair.get(1);
            graph.computeIfAbsent(word1, k -> new ArrayList<>()).add(word2);
            graph.computeIfAbsent(word2, k -> new ArrayList<>()).add(word1);
        }

        // Check each position
        for (int i = 0; i < sentence1.length; i++) {
            String word1 = sentence1[i], word2 = sentence2[i];
            if (!word1.equals(word2)) {
                Set<String> visited = new HashSet<>();
                if (!dfs(word1, word2, visited, graph)) {
                    return false;
                }
            }
        }

        return true;
    }

    private boolean dfs(String start, String target, Set<String> visited, Map<String, List<String>> graph) {
        if (start.equals(target)) return true;
        visited.add(start);

        for (String neighbor : graph.getOrDefault(start, new ArrayList<>())) {
            if (!visited.contains(neighbor)) {
                if (dfs(neighbor, target, visited, graph)) {
                    return true;
                }
            }
        }
        return false;
    }
}

