class Main {
    public static int solution(int[][] intervals) {
        if (intervals.length == 0) return 0;

        // Sort intervals by end point
        Arrays.sort(intervals, (a, b) -> Integer.compare(a[1], b[1]));

        // Track the last two numbers added to the set
        int p1 = -1, p2 = -1;
        int count = 0;

        for (int[] interval : intervals) {
            int start = interval[0], end = interval[1];

            if (p1 < start) {
                // Neither p1 nor p2 are in current interval
                p1 = end - 1;
                p2 = end;
                count += 2;
            } else if (p2 < start) {
                // Only p1 is in current interval
                p1 = p2;
                p2 = end;
                count += 1;
            }
            // If both p1 and p2 are in interval, continue
        }

        return count;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine().trim();

        // Parse 2D array
        line = line.substring(1, line.length() - 1); // Remove outer brackets
        String[] parts = line.split("],\\[");
        int[][] intervals = new int[parts.length][];

        for (int i = 0; i < parts.length; i++) {
            String part = parts[i].replaceAll("[\\[\\]]", "");
            String[] nums = part.split(",");
            intervals[i] = new int[nums.length];
            for (int j = 0; j < nums.length; j++) {
                intervals[i][j] = Integer.parseInt(nums[j].trim());
            }
        }

        System.out.println(solution(intervals));
    }
