int solution(vector<vector<int>>& intervals) {
    if (intervals.empty()) return 0;

    // Sort intervals by end point
    sort(intervals.begin(), intervals.end(), [](const vector<int>& a, const vector<int>& b) {
        return a[1] < b[1];
    });

    // Track the last two numbers added to the set
    int p1 = -1, p2 = -1;
    int count = 0;

    for (const auto& interval : intervals) {
        int start = interval[0], end = interval[1];

        if (p1 < start) {
            // Neither p1 nor p2 are in current interval
            p1 = end - 1;
            p2 = end;
            count += 2;
        } else if (p2 < start) {
            // Only p1 is in current interval
            p1 = p2;
            p2 = end;
            count += 1;
        }
        // If both p1 and p2 are in interval, continue
    }

    return count;
}

