import (
    "sort"
)

func shortestDistanceColor(colors []int, queries [][]int) []int {
    // Preprocess: store indices for each color
    colorIndices := make(map[int][]int)

    for i, color := range colors {
        colorIndices[color] = append(colorIndices[color], i)
    }

    result := make([]int, 0, len(queries))

    for _, query := range queries {
        index := query[0]
        targetColor := query[1]

        indices, exists := colorIndices[targetColor]
        if !exists || len(indices) == 0 {
            result = append(result, -1)
            continue
        }

        pos := sort.SearchInts(indices, index)
        minDist := 1<<31 - 1 // Use max int32 instead of math.MaxInt32

        // Check index at pos
        if pos < len(indices) {
            dist := abs(indices[pos] - index)
            if dist < minDist {
                minDist = dist
            }
        }

        // Check index at pos-1
        if pos > 0 {
            dist := abs(indices[pos-1] - index)
            if dist < minDist {
                minDist = dist
            }
        }

        result = append(result, minDist)
    }

    return result
}

func abs(x int) int {
    if x < 0 {
        return -x
    }
    return x
}

