import java.util.*;
import java.io.*;

class Main {
    static class UnionFind {
        int[] parent;

        UnionFind(int n) {
            parent = new int[n];
            for (int i = 0; i < n; i++) {
                parent[i] = i;
            }
        }

        int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]);
            }
            return parent[x];
        }

        void union(int x, int y) {
            int px = find(x), py = find(y);
            if (px != py) {
                parent[px] = py;
            }
        }
    }

    public static String solution(String s, int[][] pairs) {
        int n = s.length();
        UnionFind uf = new UnionFind(n);

        // Union connected positions
        for (int[] pair : pairs) {
            uf.union(pair[0], pair[1]);
        }

        // Group positions by root
        Map<Integer, List<Integer>> groups = new HashMap<>();
        for (int i = 0; i < n; i++) {
            int root = uf.find(i);
            groups.computeIfAbsent(root, k -> new ArrayList<>()).add(i);
        }

        // Sort characters within each group
        char[] result = s.toCharArray();
        for (List<Integer> positions : groups.values()) {
            List<Character> chars = new ArrayList<>();
            for (int pos : positions) {
                chars.add(s.charAt(pos));
            }
            Collections.sort(chars);
            Collections.sort(positions);

            for (int i = 0; i < positions.size(); i++) {
                result[positions.get(i)] = chars.get(i);
            }
        }

        return new String(result);
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String s = br.readLine().trim();
        String pairsStr = br.readLine().trim();

        // Parse pairs array
        int[][] pairs;
        if (pairsStr.equals("[]")) {
            pairs = new int[0][0];
        } else {
            pairsStr = pairsStr.substring(1, pairsStr.length() - 1); // Remove []
            String[] pairStrings = pairsStr.split("],\\s*\\[");
            pairs = new int[pairStrings.length][2];
            for (int i = 0; i < pairStrings.length; i++) {
                String pair = pairStrings[i].replaceAll("\\[|\\]", "").trim();
                String[] nums = pair.split(",");
                pairs[i][0] = Integer.parseInt(nums[0].trim());
                pairs[i][1] = Integer.parseInt(nums[1].trim());
            }
        }

        System.out.println(solution(s, pairs));
    }
}

