#include <iostream>
#include <vector>
#include <string>
#include <unordered_map>
#include <algorithm>
#include <sstream>
#include <regex>
using namespace std;

class UnionFind {
public:
    vector<int> parent;

    UnionFind(int n) : parent(n) {
        for (int i = 0; i < n; i++) {
            parent[i] = i;
        }
    }

    int find(int x) {
        if (parent[x] != x) {
            parent[x] = find(parent[x]);
        }
        return parent[x];
    }

    void unite(int x, int y) {
        int px = find(x), py = find(y);
        if (px != py) {
            parent[px] = py;
        }
    }
};

string solution(string s, vector<vector<int>>& pairs) {
    int n = s.length();
    UnionFind uf(n);

    // Union connected positions
    for (auto& pair : pairs) {
        uf.unite(pair[0], pair[1]);
    }

    // Group positions by root
    unordered_map<int, vector<int>> groups;
    for (int i = 0; i < n; i++) {
        groups[uf.find(i)].push_back(i);
    }

    // Sort characters within each group
    string result = s;
    for (auto& [root, positions] : groups) {
        vector<char> chars;
        for (int pos : positions) {
            chars.push_back(s[pos]);
        }
        sort(chars.begin(), chars.end());
        sort(positions.begin(), positions.end());

        for (int i = 0; i < positions.size(); i++) {
            result[positions[i]] = chars[i];
        }
    }

    return result;
}

int main() {
    string s;
    getline(cin, s);

    string pairsLine;
    getline(cin, pairsLine);

    vector<vector<int>> pairs;
    if (pairsLine != "[]") {
        // Remove outer brackets
        pairsLine = pairsLine.substr(1, pairsLine.length() - 2);

        // Use regex to find all [a,b] patterns
        regex pairRegex("\\[([0-9]+),([0-9]+)\\]");
        sregex_iterator iter(pairsLine.begin(), pairsLine.end(), pairRegex);
        sregex_iterator end;

        while (iter != end) {
            smatch match = *iter;
            int a = stoi(match[1].str());
            int b = stoi(match[2].str());
            pairs.push_back({a, b});
            ++iter;
        }
    }

    cout << solution(s, pairs) << endl;
    return 0;
}

