#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int parent[100000];

int find(int x) {
    if (parent[x] != x) {
        parent[x] = find(parent[x]);
    }
    return parent[x];
}

void unite(int x, int y) {
    int px = find(x), py = find(y);
    if (px != py) {
        parent[px] = py;
    }
}

int compare_char(const void *a, const void *b) {
    return *(char*)a - *(char*)b;
}

int compare_int(const void *a, const void *b) {
    return *(int*)a - *(int*)b;
}

char* solution(char* s, int pairs[][2], int pairsSize) {
    int n = strlen(s);

    // Initialize Union-Find
    for (int i = 0; i < n; i++) {
        parent[i] = i;
    }

    // Union connected positions
    for (int i = 0; i < pairsSize; i++) {
        unite(pairs[i][0], pairs[i][1]);
    }

    // Group positions by root and sort
    int visited[100000] = {0};
    char* result = malloc((n + 1) * sizeof(char));
    strcpy(result, s);

    for (int i = 0; i < n; i++) {
        if (visited[i]) continue;

        // Find all positions in same group
        int positions[100000], posCount = 0;
        char chars[100000];

        for (int j = 0; j < n; j++) {
            if (find(j) == find(i)) {
                positions[posCount] = j;
                chars[posCount] = s[j];
                posCount++;
                visited[j] = 1;
            }
        }

        // Sort both arrays
        qsort(chars, posCount, sizeof(char), compare_char);
        qsort(positions, posCount, sizeof(int), compare_int);

        // Assign sorted chars to sorted positions
        for (int k = 0; k < posCount; k++) {
            result[positions[k]] = chars[k];
        }
    }

    return result;
}

int main() {
    char s[100001];
    fgets(s, sizeof(s), stdin);
    s[strcspn(s, "\n")] = 0;

    int pairs[100000][2];
    int pairsSize = 0;

    char pairsLine[1000000];
    fgets(pairsLine, sizeof(pairsLine), stdin);

    // Parse pairs using simple string scanning
    char* ptr = pairsLine;
    while (*ptr) {
        if (*ptr == '[' && *(ptr+1) != ']') {
            ptr++;
            int a, b;
            if (sscanf(ptr, "%d,%d", &a, &b) == 2) {
                pairs[pairsSize][0] = a;
                pairs[pairsSize][1] = b;
                pairsSize++;
                // Skip to next potential pair
                while (*ptr && *ptr != ']') ptr++;
            }
        }
        if (*ptr) ptr++;
    }

    char* result = solution(s, pairs, pairsSize);
    printf("%s\n", result);
    free(result);
    return 0;
}

