class Main {
    public static int[] solution(int[] nums) {
        int n = nums.length;

        // Selection sort with custom comparison
        for (int i = 0; i < n; i++) {
            int minIdx = i;
            for (int j = i + 1; j < n; j++) {
                int freqMin = countFrequency(nums, nums[minIdx]);
                int freqJ = countFrequency(nums, nums[j]);

                boolean shouldSelect = false;
                if (freqJ < freqMin) {
                    shouldSelect = true;
                } else if (freqJ == freqMin && nums[j] > nums[minIdx]) {
                    shouldSelect = true;
                }

                if (shouldSelect) {
                    minIdx = j;
                }
            }

            // Swap with position i
            if (minIdx != i) {
                int temp = nums[i];
                nums[i] = nums[minIdx];
                nums[minIdx] = temp;
            }
        }

        return nums;
    }

    private static int countFrequency(int[] nums, int target) {
        int count = 0;
        for (int num : nums) {
            if (num == target) count++;
        }
        return count;
    }

