vector<vector<int>> solution(vector<vector<int>>& score, int k) {
    int m = score.size();
    // Bubble sort based on k-th column
    for (int i = 0; i < m; i++) {
        for (int j = 0; j < m - 1; j++) {
            // If current row's k-th score < next row's k-th score, swap
            if (score[j][k] < score[j + 1][k]) {
                swap(score[j], score[j + 1]);
            }
        }
    }
    return score;
}

