import java.util.*;
import java.io.*;

class Main {
    public static int solution(int[] nums, int target) {
        int total = 0;
        for (int num : nums) {
            total += num;
        }

        // Edge cases
        if (target > total || target < -total || (total + target) % 2 == 1) {
            return 0;
        }

        // Transform: find subsets that sum to (total + target) / 2
        int subsetSum = (total + target) / 2;

        // DP: count ways to make subsetSum
        int[] dp = new int[subsetSum + 1];
        dp[0] = 1; // One way to make sum 0: choose nothing

        for (int num : nums) {
            // Iterate backwards to avoid using same number twice
            for (int j = subsetSum; j >= num; j--) {
                dp[j] += dp[j - num];
            }
        }

        return dp[subsetSum];
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String line = br.readLine().trim();
        // Remove brackets and split by comma
        line = line.substring(1, line.length() - 1);
        String[] numsStr = line.split(",");
        int[] nums = new int[numsStr.length];
        for (int i = 0; i < numsStr.length; i++) {
            nums[i] = Integer.parseInt(numsStr[i].trim());
        }
        int target = Integer.parseInt(br.readLine().trim());

        int result = solution(nums, target);
        System.out.println(result);
    }
}

