class DiningPhilosophers {
    constructor() {
        this.forks = Array(5).fill(null).map(() => ({ locked: false, waitQueue: [] }));
    }

    async acquireFork(forkId) {
        while (this.forks[forkId].locked) {
            await new Promise(resolve => this.forks[forkId].waitQueue.push(resolve));
        }
        this.forks[forkId].locked = true;
    }

    releaseFork(forkId) {
        this.forks[forkId].locked = false;
        if (this.forks[forkId].waitQueue.length > 0) {
            const resolve = this.forks[forkId].waitQueue.shift();
            resolve();
        }
    }

    async wantsToEat(philosopher, pickLeftFork, pickRightFork, eat, putLeftFork, putRightFork) {
        const leftFork = philosopher;
        const rightFork = (philosopher + 1) % 5;

        if (philosopher % 2 === 0) {
            // Even philosophers pick right fork first
            await this.acquireFork(rightFork);
            pickRightFork();
            await this.acquireFork(leftFork);
            pickLeftFork();
            eat();
            putLeftFork();
            this.releaseFork(leftFork);
            putRightFork();
            this.releaseFork(rightFork);
        } else {
            // Odd philosophers pick left fork first
            await this.acquireFork(leftFork);
            pickLeftFork();
            await this.acquireFork(rightFork);
            pickRightFork();
            eat();
            putRightFork();
            this.releaseFork(rightFork);
            putLeftFork();
            this.releaseFork(leftFork);
        }
    }
}

