#include <iostream>
#include <mutex>
#include <string>
#include <functional>
#include <condition_variable>

class TrafficLight {
public:
    std::mutex roadMutex;
    std::condition_variable cvA, cvB;
    bool semaphoreA = true;
    bool semaphoreB = true;
    int currentRoad = 1;
    int carsOnRoad = 0;

    void carArrived(int carId, int roadId, int direction,
                   std::function<void()> turnGreen,
                   std::function<void()> crossCar) {
        std::unique_lock<std::mutex> lock(roadMutex);

        // Wait for semaphore
        if (roadId == 1) {
            cvA.wait(lock, [this] { return semaphoreA; });
            semaphoreA = false;
        } else {
            cvB.wait(lock, [this] { return semaphoreB; });
            semaphoreB = false;
        }

        if (currentRoad != roadId) {
            turnGreen();
            currentRoad = roadId;
        }
        carsOnRoad++;

        lock.unlock();
        crossCar();
        lock.lock();

        carsOnRoad--;

        // Release semaphore
        if (roadId == 1) {
            semaphoreA = true;
            cvA.notify_one();
        } else {
            semaphoreB = true;
            cvB.notify_one();
        }
    }
};

std::string solution() {
    TrafficLight trafficLight;
    return "Enhanced TrafficLight system initialized";
}

int main() {
    std::cout << solution() << std::endl;
    return 0;
}

