        carsOnRoad:  0,
    }
    // Initialize semaphores
    tl.semaphoreA <- struct{}{}
    tl.semaphoreB <- struct{}{}
    return tl
}

func (tl *TrafficLight) carArrived(carId, roadId, direction int, turnGreen, crossCar func()) {
    semaphore := tl.semaphoreA
    if roadId == 2 {
        semaphore = tl.semaphoreB
    }

    <-semaphore // acquire

    tl.roadMutex.Lock()
    if tl.currentRoad != roadId {
        turnGreen()
        tl.currentRoad = roadId
    }
    tl.carsOnRoad++
    tl.roadMutex.Unlock()

    crossCar()

    tl.roadMutex.Lock()
    tl.carsOnRoad--
    tl.roadMutex.Unlock()

    semaphore <- struct{}{} // release
}

func solution() string {
    trafficLight := NewTrafficLight()
    _ = trafficLight
    return "Enhanced TrafficLight system initialized"
}

