type PersonDiff struct {
    diff  int
    index int
}

func solution(costs [][]int) int {
    n := len(costs) / 2

    // Create slice of cost differences with indices
    var diffWithIndex []PersonDiff
    for i, cost := range costs {
        diff := cost[0] - cost[1]
        diffWithIndex = append(diffWithIndex, PersonDiff{diff, i})
    }

    // Sort by difference
    sort.Slice(diffWithIndex, func(i, j int) bool {
        return diffWithIndex[i].diff < diffWithIndex[j].diff
    })

    totalCost := 0

    // First n people (most negative differences, prefer city A) go to city A
    for i := 0; i < n; i++ {
        personIdx := diffWithIndex[i].index
        totalCost += costs[personIdx][0]
    }

    // Remaining n people go to city B
    for i := n; i < 2*n; i++ {
        personIdx := diffWithIndex[i].index
        totalCost += costs[personIdx][1]
    }

