#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    int diff;
    int index;
} PersonDiff;

int compare(const void* a, const void* b) {
    PersonDiff* pa = (PersonDiff*)a;
    PersonDiff* pb = (PersonDiff*)b;
    return pa->diff - pb->diff;
}

int solution(int costs[][2], int costsSize) {
    int n = costsSize / 2;

    // Create array of cost differences with indices
    PersonDiff* diffWithIndex = malloc(costsSize * sizeof(PersonDiff));
    for (int i = 0; i < costsSize; i++) {
        diffWithIndex[i].diff = costs[i][0] - costs[i][1];
        diffWithIndex[i].index = i;
    }

    // Sort by difference
    qsort(diffWithIndex, costsSize, sizeof(PersonDiff), compare);

    int totalCost = 0;

    // First n people (most negative differences, prefer city A) go to city A
    for (int i = 0; i < n; i++) {
        int personIdx = diffWithIndex[i].index;
        totalCost += costs[personIdx][0];
    }

    // Remaining n people go to city B
    for (int i = n; i < 2 * n; i++) {
        int personIdx = diffWithIndex[i].index;
        totalCost += costs[personIdx][1];
    }

    free(diffWithIndex);
    return totalCost;
}

int main() {
    char line[10000];
    fgets(line, sizeof(line), stdin);

    int costs[100][2];
    int costsSize = 0;

    char* ptr = line + 1;
    while (*ptr && *ptr != ']') {
        if (*ptr == '[') {
            ptr++;
            costs[costsSize][0] = atoi(ptr);
            while (*ptr && *ptr != ',') ptr++;
            ptr++;
            costs[costsSize][1] = atoi(ptr);
            while (*ptr && *ptr != ']') ptr++;
            costsSize++;
        }
        ptr++;
    }

    printf("%d\n", solution(costs, costsSize));
    return 0;
}

