class Main {
    public static List<String> solution(String s, List<String> wordDict) {
        Set<String> wordSet = new HashSet<>(wordDict);
        return backtrack(s, wordSet, 0);
    }

    private static List<String> backtrack(String s, Set<String> wordSet, int start) {
        if (start == s.length()) {
            List<String> result = new ArrayList<>();
            result.add("");
            return result;
        }

        List<String> result = new ArrayList<>();
        for (int end = start + 1; end <= s.length(); end++) {
            String word = s.substring(start, end);
            if (wordSet.contains(word)) {
                List<String> subSentences = backtrack(s, wordSet, end);
                for (String sentence : subSentences) {
                    result.add(word + (sentence.isEmpty() ? "" : " " + sentence));
                }
            }
        }

        return result;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String s = br.readLine().trim();
        String jsonArray = br.readLine().trim();

        Gson gson = new Gson();
        String[] wordsArray = gson.fromJson(jsonArray, String[].class);
        List<String> wordDict = Arrays.asList(wordsArray);

        List<String> result = solution(s, wordDict);
        String output = gson.toJson(result);
        System.out.println(output);
    }
