import java.util.*;
import java.io.*;
import com.google.gson.*;

class Main {
    private static Set<String> wordSet;

    public static List<String> solution(String s, List<String> wordDict) {
        wordSet = new HashSet<>(wordDict);
        return backtrack(s, 0);
    }

    private static boolean canBreak(String s) {
        boolean[] dp = new boolean[s.length() + 1];
        dp[0] = true;

        for (int i = 1; i <= s.length(); i++) {
            for (int j = 0; j < i; j++) {
                if (dp[j] && wordSet.contains(s.substring(j, i))) {
                    dp[i] = true;
                    break;
                }
            }
        }

        return dp[s.length()];
    }

    private static List<String> backtrack(String s, int start) {
        if (start == s.length()) {
            List<String> result = new ArrayList<>();
            result.add("");
            return result;
        }

        if (!canBreak(s.substring(start))) {
            return new ArrayList<>();
        }

        List<String> result = new ArrayList<>();
        for (int end = start + 1; end <= s.length(); end++) {
            String word = s.substring(start, end);
            if (wordSet.contains(word)) {
                List<String> subSentences = backtrack(s, end);
                for (String sentence : subSentences) {
                    result.add(word + (sentence.isEmpty() ? "" : " " + sentence));
                }
            }
        }

        return result;
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        String s = br.readLine().trim();
        String jsonArray = br.readLine().trim();

