const fs = require('fs');
const lines = fs.readFileSync(0, 'utf8').trim().split('\n');

function solution(board, word) {
    if (!board || !board[0] || !word) return false;

    const rows = board.length, cols = board[0].length;

    // Character frequency check
    const boardChars = new Map();
    for (let row of board) {
        for (let char of row) {
            boardChars.set(char, (boardChars.get(char) || 0) + 1);
        }
    }

    const wordChars = new Map();
    for (let char of word) {
        wordChars.set(char, (wordChars.get(char) || 0) + 1);
    }

    for (let [char, count] of wordChars) {
        if ((boardChars.get(char) || 0) < count) return false;
    }

    // Optimize starting direction
    const firstCount = wordChars.get(word[0]) || 0;
    const lastCount = wordChars.get(word[word.length - 1]) || 0;
    if (firstCount > lastCount) {
        word = word.split('').reverse().join('');
    }

    function dfs(r, c, index) {
        if (index === word.length) return true;

        if (r < 0 || r >= rows || c < 0 || c >= cols || 
            board[r][c] !== word[index]) {
            return false;
        }

        const temp = board[r][c];
        board[r][c] = '#';

        const found = dfs(r+1, c, index+1) || 
                     dfs(r-1, c, index+1) || 
                     dfs(r, c+1, index+1) || 
                     dfs(r, c-1, index+1);

        board[r][c] = temp;
        return found;
    }

    for (let i = 0; i < rows; i++) {
        for (let j = 0; j < cols; j++) {
            if (board[i][j] === word[0] && dfs(i, j, 0)) {
                return true;
            }
        }
    }

    return false;
}

